INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (1, 1, 'Артикль הַ ставится перед существительным слитно', '[{"he": "הַסֵּפֶר", "ru": "книга (определённая)", "translit": "hа-сЕфер"}, {"he": "הַיֶּלֶד", "ru": "мальчик (определённый)", "translit": "hа-йЕлед"}]', '[{"text": "Перед ח и ע артикль читается как הֶ (hэ): הֶחָבֵר — друг"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (2, 1, 'Неопределённое существительное — без артикля', '[{"he": "סֵפֶר", "ru": "книга (какая-то)", "translit": "сЕфер"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (3, 2, 'Женский род обычно заканчивается на -ה или -ת', '[{"he": "יַלְדָּה", "ru": "девочка", "translit": "ялдА"}, {"he": "מִשְׁמֶרֶת", "ru": "смена/вахта", "translit": "мишмЕрет"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (4, 2, 'Множественное число м.р. — окончание -ים, ж.р. — окончание -ות', '[{"he": "יְלָדִים", "ru": "мальчики", "translit": "еладИм"}, {"he": "יַלְדּוֹת", "ru": "девочки", "translit": "ялдОт"}]', '[{"text": "Есть исключения: שׁוּלְחָן (м.р.) → שׁוּלְחָנוֹת (окончание ж.р.)"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (5, 3, 'Местоимения не склоняются, но различаются по роду во 2-м и 3-м лице', '[{"he": "אַתָּה לוֹמֵד", "ru": "ты (м.) учишь", "translit": "атА ломЕд"}, {"he": "אַתְּ לוֹמֶדֶת", "ru": "ты (ж.) учишь", "translit": "ат ломЕдет"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (6, 13, 'Реальное условие: אם + будущее время в обеих частях', '[{"he": "אם תלמד, תצליח", "ru": "Если будешь учиться, преуспеешь", "translit": "им тилмАд, тацлИах"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (7, 13, 'Нереальное условие: אילו/לו + прошедшее время', '[{"he": "אילו ידעתי, הייתי בא", "ru": "Если бы я знал, я бы пришёл", "translit": "илУ ядАти, hаИти ба"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (8, 15, 'Относительное придаточное с ש- после существительного', '[{"he": "הספר שקראתי", "ru": "книга, которую я прочитал", "translit": "hа-сЕфер ше-карАти"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (9, 15, 'После предлогов добавляется местоимённый суффикс', '[{"he": "הילד שדיברתי איתו", "ru": "мальчик, с которым я говорил", "translit": "hа-йЕлед ше-дибАрти итО"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (10, 16, 'Модальные слова + инфинитив', '[{"he": "אני צריך ללמוד", "ru": "я должен учиться", "translit": "анИ царИх лилмОд"}, {"he": "היא יכולה לבוא", "ru": "она может прийти", "translit": "hи ехолА лавО"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (11, 18, 'Придаточные времени с כש- и אחרי ש-', '[{"he": "כשהגעתי, הם כבר ישנו", "ru": "Когда я пришёл, они уже спали", "translit": "кше-hигАти, hем квар яшнУ"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (12, 21, 'Предлоги склоняются по лицам', '[{"he": "הוא נתן לי את הספר שלו", "ru": "Он дал мне свою книгу", "translit": "hу натАн ли эт hа-сЕфер шелО"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (13, 22, 'Отглагольные существительные сохраняют корень', '[{"he": "הכתיבה שלו יפה", "ru": "Его почерк красив", "translit": "hа-ктивА шелО яфА"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (14, 25, 'Инверсия в высоком стиле: сказуемое перед подлежащим', '[{"he": "בא האביב", "ru": "Пришла весна", "translit": "ба hа-авИв"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (15, 28, 'Идиома: שבר את הראש = долго думал', '[{"he": "שברתי את הראש על זה", "ru": "Я долго думал об этом", "translit": "шавАрти эт hа-рош аль зе"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (16, 33, 'Инфинитив с ב- и суффиксом указывает на одновременность: בהגיעו = когда он прибыл', '[{"he": "בהגיעו הביתה, מצא מכתב", "ru": "Когда он пришёл домой, нашёл письмо", "translit": "бе-hагиО hа-бАйта, мацА михтАв"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (17, 34, 'Нифъаль в стативном значении описывает состояние, а не действие: נראה = выглядит', '[{"he": "היא נראית עצובה היום", "ru": "Она выглядит грустной сегодня", "translit": "hи нирЭйт ацувА hа-йОм"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (18, 35, 'Средневековые термины часто образованы по модели hе-существительное от корня: השגחה от ש.ג.ח (наблюдать), הנהלה от נ.ה.ל (управлять), השפעה от ש.פ.ע (влиять)', '[{"he": "המסעדה הזו תחת השגחה של הרבנות", "ru": "Этот ресторан под наблюдением раввината", "translit": "hа-мисадА hа-зОт тАхат hашгахА шель hа-рабанУт"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (19, 36, 'Маркеры высокого регистра: אולם (однако), לפיכך (поэтому), יתרה מזאת (более того). Маркеры разговорного: ялла (יאללה), сабаба (סבבה), стам (סתם).', '[{"he": "אולם, יש לציין כי המצב שונה — но в разговоре: אבל תראה, זה לא אותו דבר", "ru": "Однако следует отметить, что ситуация иная — но в разговоре: слушай, это совсем другое дело", "translit": "улАм, йеш лецайЕн ки hа-мацАв шонЕ — авАль тирЭ, зе ло отО давАр"}]', 'null');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (20, 89, 'Вопросительное слово стоит в начале предложения и определяет тип ожидаемого ответа', '[{"he": "מי אתה?", "ru": "Кто ты?", "translit": "ми атА?"}, {"he": "מה אתה עושה?", "ru": "Что ты делаешь?", "translit": "ма атА осЕ?"}, {"he": "איפה אתה גר?", "ru": "Где ты живёшь?", "translit": "эйфО атА гар?"}]', '[{"text": "В разговорной речи вопрос может начинаться без вопросительного слова, передаваясь интонацией"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (36, 95, 'Глаголы с последним ה в 1-м и 2-м лице заменяют ה на י: ראה → ראיתי', '[{"he": "ראיתי סרט", "ru": "я видел фильм", "translit": "раИти сЕрет"}, {"he": "קניתי ספר", "ru": "я купил книгу", "translit": "канИти сЕфер"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (21, 89, 'Частица האם используется для вопросов типа «да/нет» в формальной речи', '[{"he": "האם אתה מבין?", "ru": "Ты понимаешь?", "translit": "hаИм атА мевИн?"}, {"he": "האם יש לך זמן?", "ru": "У тебя есть время?", "translit": "hаИм йеш лехА зман?"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (22, 89, 'Вопросительные слова מאין и לאן используются для направления движения', '[{"he": "מאין אתה?", "ru": "Откуда ты?", "translit": "меАйин атА?"}, {"he": "לאן אתה הולך?", "ru": "Куда ты идёшь?", "translit": "леАн атА hолЕх?"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (23, 90, 'Частица לא ставится перед глаголом для отрицания действия во всех временах', '[{"he": "אני לא יודע", "ru": "Я не знаю", "translit": "анИ ло йодЕа"}, {"he": "הוא לא בא אתמול", "ru": "Он не пришёл вчера", "translit": "hу ло ба этмОль"}, {"he": "אני לא אבוא מחר", "ru": "Я не приду завтра", "translit": "анИ ло авО махАр"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (24, 90, 'Частица אין отрицает существование и используется вместо יש в отрицательных конструкциях обладания', '[{"he": "אין לי כסף", "ru": "У меня нет денег", "translit": "эйн ли кЕсеф"}, {"he": "אין כאן בעיה", "ru": "Здесь нет проблемы", "translit": "эйн кан беайА"}]', '[{"text": "В литературном иврите אין спрягается: אינני, אינך, אינו, אינה и т.д."}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (25, 90, 'Частица אל используется для запрета и ставится перед глаголом в будущем времени', '[{"he": "אל תלך!", "ru": "Не ходи!", "translit": "аль телЕх!"}, {"he": "אל תשכח!", "ru": "Не забудь!", "translit": "аль тишкАх!"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (26, 91, 'Конструкция של + местоимённый суффикс — аналитический способ выражения принадлежности', '[{"he": "הספר שלי", "ru": "моя книга", "translit": "hа-сЕфер шелИ"}, {"he": "הבית שלנו", "ru": "наш дом", "translit": "hа-бАйит шелАну"}, {"he": "החברה שלו", "ru": "его подруга", "translit": "hа-хаверА шелО"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (27, 91, 'Притяжательные суффиксы присоединяются к основе существительного, которая может изменяться', '[{"he": "סִפְרִי", "ru": "моя книга", "translit": "сифрИ"}, {"he": "בֵּיתִי", "ru": "мой дом", "translit": "бейтИ"}]', '[{"text": "Основа слова часто меняется при добавлении суффикса: סֵפֶר → סִפְר-, בַּיִת → בֵּית-"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (28, 92, 'Указательные местоимения в функции определения ставятся после существительного с артиклем', '[{"he": "הספר הזה", "ru": "эта книга", "translit": "hа-сЕфер hа-зЕ"}, {"he": "הילדה הזאת", "ru": "эта девочка", "translit": "hа-ялдА hа-зОт"}, {"he": "הילדים האלה", "ru": "эти дети", "translit": "hа-еладИм hа-Эле"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (29, 92, 'זה может выступать связкой «это есть» в именных предложениях', '[{"he": "זה הספר שלי", "ru": "Это моя книга", "translit": "зэ hа-сЕфер шелИ"}, {"he": "זאת המורה שלנו", "ru": "Это наша учительница", "translit": "зот hа-морА шелАну"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (30, 93, 'Числительные от 3 до 10 подчиняются правилу обратного согласования: с мужским родом существительного используется женская форма числительного и наоборот', '[{"he": "שלושה ילדים", "ru": "три мальчика", "translit": "шлошА еладИм"}, {"he": "שלוש ילדות", "ru": "три девочки", "translit": "шалОш ялдОт"}, {"he": "חמישה ספרים", "ru": "пять книг", "translit": "хамишА сфарИм"}]', '[{"text": "В разговорном иврите правило часто нарушается, используется женская форма для обоих родов"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (31, 93, 'Числительные 1 и 2 согласуются напрямую с родом существительного', '[{"he": "ילד אחד", "ru": "один мальчик", "translit": "йЕлед эхАд"}, {"he": "ילדה אחת", "ru": "одна девочка", "translit": "ялдА ахАт"}, {"he": "שני ספרים", "ru": "две книги", "translit": "шнЕй сфарИм"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (32, 94, 'Настоящее время Пааль имеет 4 формы по роду и числу, без различения лиц', '[{"he": "אני כותב / אתה כותב / הוא כותב", "ru": "я пишу / ты пишешь / он пишет", "translit": "анИ котЕв / атА котЕв / hу котЕв"}, {"he": "היא כותבת", "ru": "она пишет", "translit": "hи котЕвет"}, {"he": "הם כותבים", "ru": "они пишут", "translit": "hем котвИм"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (33, 94, 'Пустые глаголы (с ו/י в корне) имеют сокращённую форму в настоящем времени', '[{"he": "הוא קם", "ru": "он встаёт", "translit": "hу кам"}, {"he": "היא שרה", "ru": "она поёт", "translit": "hи шарА"}]', '[{"text": "Основная гласная в пустых глаголах — камац (а), а не холам (о) стандартной модели"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (34, 95, 'Прошедшее время образуется добавлением личных окончаний к корню: -תי, -תָ, -תְ, -(без), -ה, -נו, -תם, -ו', '[{"he": "כתבתי מכתב", "ru": "я написал письмо", "translit": "катАвти михтАв"}, {"he": "היא כתבה סיפור", "ru": "она написала рассказ", "translit": "hи катвА сипУр"}, {"he": "הם כתבו שיר", "ru": "они написали стихотворение", "translit": "hем катвУ шир"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (35, 95, 'Пустые глаголы теряют среднюю букву корня в прошедшем времени и имеют модель קַמְתִּי', '[{"he": "קמתי מוקדם", "ru": "я встал рано", "translit": "кАмти мукдАм"}, {"he": "הוא בא אתמול", "ru": "он пришёл вчера", "translit": "hу ба этмОль"}]', '[{"text": "Форма 3-го лица м.р. ед.ч. совпадает с корневой формой: קָם, בָּא, שָׂם"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (37, 96, 'Будущее время образуется приставками א, ת, י, נ к корню, с возможными суффиксами -י, -ו для ж.р. и мн.ч.', '[{"he": "אני אכתוב", "ru": "я напишу", "translit": "анИ эхтОв"}, {"he": "הוא יכתוב", "ru": "он напишет", "translit": "hу йихтОв"}, {"he": "אנחנו נכתוב", "ru": "мы напишем", "translit": "анАхну нихтОв"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (38, 96, 'В разговорном иврите будущее время часто заменяет повелительное наклонение для вежливых просьб', '[{"he": "תכתוב לי?", "ru": "Напишешь мне?", "translit": "тихтОв ли?"}, {"he": "תביא מים, בבקשה", "ru": "Принеси воды, пожалуйста", "translit": "тавИ мАйим, бевакашА"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (39, 97, 'В цепочке смихута артикль ставится только на последнее слово (сомех), определяя всю конструкцию', '[{"he": "בית הספר", "ru": "школа (определённая)", "translit": "бейт hа-сЕфер"}, {"he": "חדר השינה", "ru": "спальня (определённая)", "translit": "хадАр hа-шенА"}, {"he": "שר משרד החוץ", "ru": "министр иностранных дел", "translit": "сар мисрАд hа-хуц"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (40, 97, 'Первое слово (нисмах) во множественном числе мужского рода меняет окончание -ים на -י', '[{"he": "ספרי הילדים", "ru": "книги детей", "translit": "сифрЕй hа-еладИм"}, {"he": "בתי הספר", "ru": "школы", "translit": "батЕй hа-сЕфер"}]', '[{"text": "Женское множественное -ות в смихуте не изменяется: ילדות בית הספר"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (41, 97, 'Прилагательное, относящееся к первому слову смихута, ставится после всей конструкции', '[{"he": "בית הספר הגדול", "ru": "большая школа", "translit": "бейт hа-сЕфер hа-гадОль"}, {"he": "חדר השינה הקטן", "ru": "маленькая спальня", "translit": "хадАр hа-шенА hа-катАн"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (42, 98, 'Действительное причастие (בינוני פועל) по модели קוֹטֵל совпадает с настоящим временем и может быть существительным', '[{"he": "הכותב הזה מפורסם", "ru": "Этот автор (пишущий) знаменит", "translit": "hа-котЕв hа-зЕ мефурсАм"}, {"he": "הנוהג נסע מהר", "ru": "Водитель (ведущий) ехал быстро", "translit": "hа-ноhЕг насА маhЕр"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (43, 98, 'Страдательное причастие (בינוני פעול) по модели קָטוּל выражает результат действия и функционирует как прилагательное', '[{"he": "הדלת סגורה", "ru": "Дверь закрыта", "translit": "hа-дЕлет сгурА"}, {"he": "הספר כתוב בעברית", "ru": "Книга написана на иврите", "translit": "hа-сЕфер катУв бе-иврИт"}, {"he": "החלון פתוח", "ru": "Окно открыто", "translit": "hа-халОн патУах"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (44, 99, 'Инфинитив начинается с приставки ל- и имеет свою модель для каждого биньяна', '[{"he": "לכתוב", "ru": "писать (Пааль)", "translit": "лихтОв"}, {"he": "לדבר", "ru": "говорить (Пиэль)", "translit": "ледабЕр"}, {"he": "להזכיר", "ru": "напомнить (Хифъиль)", "translit": "леhазкИр"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (45, 99, 'Инфинитив сочетается с предлогами כדי, לפני, אחרי, במקום для выражения цели, времени, замены', '[{"he": "באתי כדי ללמוד", "ru": "Я пришёл, чтобы учиться", "translit": "бАти кдЕй лильмОд"}, {"he": "לפני לישון, קראתי ספר", "ru": "Перед сном я прочитал книгу", "translit": "лифнЕй лишОн, карАти сЕфер"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (46, 99, 'Инфинитив может выступать подлежащим предложения со связкой זה', '[{"he": "ללמוד עברית זה כיף", "ru": "Учить иврит — это весело", "translit": "лильмОд иврИт зэ кейф"}, {"he": "לגור בישראל זה חלום", "ru": "Жить в Израиле — это мечта", "translit": "лагУр бе-йисраЕль зэ халОм"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (47, 100, 'Модальные слова צריך, יכול, רוצה, חייב сочетаются с инфинитивом и согласуются по роду и числу', '[{"he": "אני צריך ללמוד", "ru": "Мне надо учиться", "translit": "анИ царИх лильмОд"}, {"he": "היא יכולה לבוא", "ru": "Она может прийти", "translit": "hи ехолА лавО"}, {"he": "אנחנו רוצים לאכול", "ru": "Мы хотим поесть", "translit": "анАхну роцИм леехОль"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (48, 100, 'Безличные модальные слова אסור, מותר, אפשר не согласуются и используются с инфинитивом', '[{"he": "אסור לעשן כאן", "ru": "Здесь запрещено курить", "translit": "асУр леашЕн кан"}, {"he": "אפשר להיכנס?", "ru": "Можно войти?", "translit": "эфшАр леhиканЕс?"}, {"he": "מותר לשבת כאן", "ru": "Здесь разрешено сидеть", "translit": "мутАр лашЕвет кан"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (49, 100, 'Модальные слова спрягаются во всех временах: в прошедшем через היה + модальное слово, в будущем через спряжение самого слова', '[{"he": "הייתי צריך ללמוד", "ru": "Мне надо было учиться", "translit": "hаИти царИх лильмОд"}, {"he": "יכולתי לבוא", "ru": "Я мог прийти", "translit": "яхОльти лавО"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (50, 101, 'Реальное условие строится с אם + настоящее/будущее время в обеих частях', '[{"he": "אם תלמד, תצליח", "ru": "Если будешь учиться, преуспеешь", "translit": "им тильмАд, тацлИах"}, {"he": "אם יש לך זמן, בוא", "ru": "Если есть время, приходи", "translit": "им йеш лехА зман, бо"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (51, 101, 'Нереальное условие строится с אילו/לו + прошедшее время + היה + причастие', '[{"he": "אילו ידעתי, הייתי בא", "ru": "Если бы я знал, я бы пришёл", "translit": "илУ ядАти, hаИти ба"}, {"he": "לו הייתי עשיר, הייתי קונה בית", "ru": "Если бы я был богат, купил бы дом", "translit": "лу hаИти ашИр, hаИти конЕ бАйит"}]', '[{"text": "В разговорном иврите нереальное условие часто строится с אם + היה: אם הייתי יודע"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (52, 102, 'Нифъаль — пассивная/рефлексивная пара биньяна Пааль, может выражать и пассив, и возвратное значение', '[{"he": "הספר נכתב בעברית", "ru": "Книга была написана на иврите", "translit": "hа-сЕфер нихтАв бе-иврИт"}, {"he": "הדלת נפתחה", "ru": "Дверь открылась", "translit": "hа-дЕлет нифтехА"}, {"he": "הוא נזכר פתאום", "ru": "Он вдруг вспомнил", "translit": "hу низкАр питОм"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (53, 102, 'Пуаль — строго пассивная пара биньяна Пиэль, всегда подразумевает внешнего агента', '[{"he": "הסיפור סופר לילדים", "ru": "Рассказ был рассказан детям", "translit": "hа-сипУр супАр ле-еладИм"}, {"he": "המכשיר תוקן", "ru": "Прибор был починен", "translit": "hа-махшИр тукАн"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (54, 102, 'Хуфъаль — пассивная пара биньяна Хифъиль, используется преимущественно в формальном стиле', '[{"he": "הוא הוזמן לישיבה", "ru": "Он был приглашён на заседание", "translit": "hу hузмАн ле-ешивА"}, {"he": "השינויים הוכנסו", "ru": "Изменения были внесены", "translit": "hа-шинуИм hухнесУ"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (55, 103, 'При переходе от прямой речи к косвенной вводный союз ש- заменяет кавычки, а местоимения и обстоятельства трансформируются', '[{"he": "הוא אמר: \"אני רוצה\" → הוא אמר שהוא רוצה", "ru": "Он сказал: «Я хочу» → Он сказал, что хочет", "translit": "hу амАр ше-hу роцЕ"}, {"he": "היא אמרה: \"אני כאן\" → היא אמרה שהיא שם", "ru": "Она сказала: «Я здесь» → Она сказала, что она там", "translit": "hи амрА ше-hи шам"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (56, 103, 'Вопросы типа «да/нет» в косвенной речи вводятся через אם, а информационные — через вопросительное слово', '[{"he": "הוא שאל אם אני בא", "ru": "Он спросил, приду ли я", "translit": "hу шаАль им анИ ба"}, {"he": "היא שאלה איפה אני גר", "ru": "Она спросила, где я живу", "translit": "hи шаалА эйфО анИ гар"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (57, 104, 'Каждый биньян имеет свою модель причастия: Пааль — קוֹטֵל, Пиэль — מְקַטֵּל, Хифъиль — מַקְטִיל, Хитпаэль — מִתְקַטֵּל', '[{"he": "הוא כותב (פעל) / מדבר (פיעל) / מזכיר (הפעיל)", "ru": "он пишет / говорит / напоминает", "translit": "котЕв / медабЕр / мазкИр"}, {"he": "היא מתלבשת (התפעל)", "ru": "она одевается", "translit": "hи митлабЕшет"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (58, 104, 'Пассивные биньяны тоже имеют причастия: Нифъаль — נִקְטָל, Пуаль — מְקוּטָּל, Хуфъаль — מוּקְטָל', '[{"he": "הספר נכתב (נפעל) / מדובר (פועל)", "ru": "книга пишется / говоримый", "translit": "нихтАв / медубАр"}, {"he": "הנושא מוזכר בספר (הופעל)", "ru": "тема упоминается в книге", "translit": "hа-носЕ музкАр ба-сЕфер"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (59, 105, 'Придаточные времени вводятся союзами כש-, לפני ש-, אחרי ש-, בזמן ש-, עד ש-', '[{"he": "כשבאתי, הם כבר ישנו", "ru": "Когда я пришёл, они уже спали", "translit": "кше-бАти, hем квар яшнУ"}, {"he": "לפני שיצאתי, בדקתי את הדואר", "ru": "Прежде чем вышел, проверил почту", "translit": "лифнЕй ше-яцАти, бадАкти эт hа-дОар"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (60, 105, 'Придаточные причины вводятся союзами כי, בגלל ש-, מכיוון ש-, а придаточные цели — כדי ש-, בשביל ש-', '[{"he": "לא באתי כי הייתי חולה", "ru": "Я не пришёл, потому что был болен", "translit": "ло бАти ки hаИти холЕ"}, {"he": "למדתי כדי שאצליח", "ru": "Я учился, чтобы преуспеть", "translit": "ламАдти кдЕй ше-ацлИах"}, {"he": "מכיוון שהגענו מאוחר, לא נכנסנו", "ru": "Поскольку мы опоздали, нас не впустили", "translit": "микевАн ше-hигАну меухАр, ло нихнАсну"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (61, 106, 'Причастия регулярно субстантивируются, превращаясь в названия профессий и ролей', '[{"he": "כותב → הכותב (писатель)", "ru": "пишущий → писатель", "translit": "котЕв → hа-котЕв"}, {"he": "נוהג → הנוהג (водитель)", "ru": "водящий → водитель", "translit": "ноhЕг → hа-ноhЕг"}, {"he": "מנהל → המנהל (директор)", "ru": "управляющий → директор", "translit": "менаhЕль → hа-менаhЕль"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (62, 106, 'Мишкали קְטִילָה и קִטּוּל — основные модели для образования отглагольных существительных от Пааль и Пиэль', '[{"he": "כתב → כתיבה (написание)", "ru": "писал → написание", "translit": "катАв → ктивА"}, {"he": "דיבר → דיבור (разговор)", "ru": "говорил → разговор", "translit": "дибЕр → дибУр"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (63, 107, 'עשוי выражает нейтральную возможность, а עלול — нежелательную возможность (риск)', '[{"he": "הוא עשוי להגיע מאוחר", "ru": "Он может прийти поздно (нейтрально)", "translit": "hу асУй леhагИа меухАр"}, {"he": "המצב עלול להחמיר", "ru": "Ситуация может ухудшиться (негативно)", "translit": "hа-мацАв алУль леhахмИр"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (64, 107, 'Конструкция אמור + инфинитив выражает ожидаемое действие (по плану, обещанию)', '[{"he": "הוא אמור להגיע בשש", "ru": "Он должен прийти в шесть (по плану)", "translit": "hу амУр леhагИа бе-шеш"}, {"he": "המשחק אמור להתחיל מחר", "ru": "Игра должна начаться завтра", "translit": "hа-мисхАк амУр леhатхИль махАр"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (65, 107, 'נוטה + инфинитив выражает склонность к действию, а רגיל — привычку', '[{"he": "הוא נוטה לשכוח", "ru": "Он склонен забывать", "translit": "hу нотЕ лишкОах"}, {"he": "אני רגיל לקום מוקדם", "ru": "Я привык вставать рано", "translit": "анИ рагИль лакУм мукдАм"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (66, 108, 'Глагольное управление в иврите фиксировано: каждый глагол требует определённого предлога', '[{"he": "חיכיתי לך (ל-)", "ru": "Я ждал тебя", "translit": "хикИти лехА"}, {"he": "חשבתי עליך (על)", "ru": "Я думал о тебе", "translit": "хашАвти алЕха"}, {"he": "בחרתי בספר הזה (ב-)", "ru": "Я выбрал эту книгу", "translit": "бахАрти ба-сЕфер hа-зЕ"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (67, 108, 'Один глагол с разными предлогами может менять значение: דיבר על (говорил о) vs דיבר עם (разговаривал с)', '[{"he": "דיברתי על הנושא", "ru": "Я говорил о теме", "translit": "дибАрти аль hа-носЕ"}, {"he": "דיברתי עם דוד", "ru": "Я разговаривал с Давидом", "translit": "дибАрти им давИд"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (68, 109, 'Активные биньяны (Пааль, Пиэль, Хифъиль) имеют пассивные пары (Нифъаль, Пуаль, Хуфъаль), а Хитпаэль — рефлексивный', '[{"he": "שמר (פעל) → נשמר (נפעל)", "ru": "охранял → был охраняем", "translit": "шамАр → нишмАр"}, {"he": "סיפר (פיעל) → סופר (פועל)", "ru": "рассказал → был рассказан", "translit": "сипЕр → супАр"}, {"he": "הזמין (הפעיל) → הוזמן (הופעל)", "ru": "пригласил → был приглашён", "translit": "hизмИн → hузмАн"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (69, 109, 'Один корень в разных биньянах образует семейство связанных значений: базовое → интенсив → каузатив → рефлексив', '[{"he": "למד → לימד → התלמד", "ru": "учился → обучал → обучался сам", "translit": "ламАд → лимЕд → hитламЕд"}, {"he": "לבש → הלביש → התלבש", "ru": "надел → одел (кого-то) → оделся", "translit": "лавАш → hильбИш → hитлабЕш"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (70, 110, 'Предлоги в иврите принимают местоимённые суффиксы, заменяя конструкцию «предлог + местоимение»', '[{"he": "אני נתתי לו (ל + הוא)", "ru": "Я дал ему", "translit": "анИ натАти лО"}, {"he": "היא דיברה איתי (עם + אני)", "ru": "Она говорила со мной", "translit": "hи дибрА итИ"}, {"he": "הוא כתב עליה (על + היא)", "ru": "Он написал о ней", "translit": "hу катАв алЕhа"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (71, 110, 'Предлог עם (с) имеет особую парадигму склонения: איתי, איתך, איתו, איתה, איתנו, איתכם, איתם', '[{"he": "בוא איתי", "ru": "Пойдём со мной", "translit": "бо итИ"}, {"he": "אני רוצה לדבר איתך", "ru": "Я хочу поговорить с тобой", "translit": "анИ роцЕ ледабЕр итхА"}]', '[{"text": "В формальном языке встречается форма עִמִּי, עִמְּךָ и т.д. вместо разговорных איתי, איתך"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (72, 111, 'Каждый биньян имеет свою модель отглагольного существительного (шем пеула)', '[{"he": "כתב → כתיבה (פעל)", "ru": "писал → написание", "translit": "катАв → ктивА"}, {"he": "דיבר → דיבור (פיעל)", "ru": "говорил → разговор", "translit": "дибЕр → дибУр"}, {"he": "השפיע → השפעה (הפעיל)", "ru": "влиял → влияние", "translit": "hишпИа → hашпаА"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (73, 111, 'Номинализация предложений позволяет свернуть целое высказывание в именную группу через смихут', '[{"he": "הממשלה החליטה → החלטת הממשלה", "ru": "правительство решило → решение правительства", "translit": "hахлатАт hа-мемшалА"}, {"he": "העובדים שבתו → שביתת העובדים", "ru": "рабочие бастовали → забастовка рабочих", "translit": "швитАт hа-овдИм"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (74, 112, 'Формальный иврит использует אשר вместо ש-, אינני вместо אני לא, и литературные союзы', '[{"he": "הספר אשר קראתי (формальный) = הספר שקראתי (разговорный)", "ru": "книга, которую я прочитал", "translit": "hа-сЕфер ашЕр карАти / ше-карАти"}, {"he": "אינני יודע (формальный) = אני לא יודע (разговорный)", "ru": "я не знаю", "translit": "эйнЕни йодЕа / анИ ло йодЕа"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (75, 112, 'В разговорном иврите различие женского множественного (תכתובנה) нейтрализуется в пользу мужской формы (תכתבו)', '[{"he": "הבנות תכתובנה (формальный) / תכתבו (разговорный)", "ru": "девочки напишут", "translit": "тихтОвна / тихтевУ"}, {"he": "הן תלמדנה (формальный) / תלמדו (разговорный)", "ru": "они (ж.) будут учиться", "translit": "тиламАдна / тильмедУ"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (76, 113, 'Топикализация — вынесение дополнения в начало предложения для выделения — маркируется частицей את', '[{"he": "את הספר הזה אני אוהב", "ru": "Эту книгу я люблю", "translit": "эт hа-сЕфер hа-зЕ анИ оhЕв"}, {"he": "את דוד ראיתי אתמול", "ru": "Давида я видел вчера", "translit": "эт давИд раИти этмОль"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (77, 113, 'Инверсия (VSO) используется в повествовательном и журналистском стиле для динамичности', '[{"he": "אמר המנהל: \"אנחנו ממשיכים\"", "ru": "Сказал директор: «Мы продолжаем»", "translit": "амАр hа-менаhЕль: анАхну мамшихИм"}, {"he": "באו האורחים מכל הארץ", "ru": "Пришли гости со всей страны", "translit": "бАу hа-орхИм ми-коль hа-Арец"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (78, 114, 'Маркеры дополнения (בנוסף, כמו כן, יתר על כן) используются для добавления аргументов', '[{"he": "בנוסף, יש לציין ש...", "ru": "Кроме того, следует отметить, что...", "translit": "бе-носАф, йеш лецайЕн ше-"}, {"he": "יתר על כן, המחקר מראה ש...", "ru": "Более того, исследование показывает, что...", "translit": "йетЕр аль кен, hа-мехкАр марЕ ше-"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (79, 114, 'Маркеры контраста (לעומת זאת, אולם, עם זאת) вводят противоположную точку зрения', '[{"he": "לעומת זאת, יש הטוענים ש...", "ru": "В то же время, есть утверждающие, что...", "translit": "леумАт зот, йеш hа-тоанИм ше-"}, {"he": "אולם, המציאות שונה", "ru": "Однако реальность иная", "translit": "улАм, hа-мециУт шонА"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (80, 114, 'Маркеры вывода (לכן, על כן, לסיכום) сигнализируют о заключении или выводе', '[{"he": "לכן, ניתן להסיק ש...", "ru": "Поэтому можно заключить, что...", "translit": "лахЕн, нитАн леhасИк ше-"}, {"he": "לסיכום, הנושא דורש מחקר נוסף", "ru": "Подводя итог, тема требует дополнительного изучения", "translit": "ле-сикУм, hа-носЕ дорЕш мехкАр носАф"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (81, 115, 'Прямая цитата вводится формулами כפי ש-, לדברי, ואלה דבריו: с двоеточием и кавычками', '[{"he": "כפי שאמר המנהל: \"אנחנו ממשיכים\"", "ru": "Как сказал директор: «Мы продолжаем»", "translit": "кефИ ше-амАр hа-менаhЕль"}, {"he": "לדברי שר החינוך: \"הרפורמה חיונית\"", "ru": "По словам министра образования: «Реформа необходима»", "translit": "ле-диврЕй сар hа-хинУх"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (82, 115, 'Косвенная цитата вводится через לטענתו, לדעתו, על פי с подчинительным союзом ש-', '[{"he": "לטענתו, המצב השתפר", "ru": "По его утверждению, ситуация улучшилась", "translit": "ле-таанатО, hа-мацАв hиштапЕр"}, {"he": "על פי המחקר, ילדים לומדים מהר", "ru": "Согласно исследованию, дети учатся быстро", "translit": "аль пи hа-мехкАр, еладИм ломдИм маhЕр"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (83, 116, 'Анафорические местоимения (הוא, היא, זה, הנ"ל) ссылаются на ранее упомянутые элементы, обеспечивая связность', '[{"he": "הילד בא. הוא ישב ליד השולחן", "ru": "Мальчик пришёл. Он сел за стол.", "translit": "hа-йЕлед ба. hу яшАв лейАд hа-шульхАн"}, {"he": "קראתי מאמר. הנ\"ל היה מעניין", "ru": "Я прочитал статью. Вышеупомянутая была интересной.", "translit": "карАти маамАр. hа-наль hайА меаньЕн"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (84, 116, 'Лексическая когезия достигается через синонимию, гиперонимию и перифразу — повторение одного и того же понятия разными словами', '[{"he": "הכלב...בעל החיים (гипероним)", "ru": "собака...животное", "translit": "hа-кЕлев...бАаль hа-хайИм"}, {"he": "ירושלים...עיר הקודש (перифраза)", "ru": "Иерусалим...Святой город", "translit": "ерушалАйим...ир hа-кОдеш"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (85, 117, 'Инфинитив абсолютный ставится перед спрягаемым глаголом того же корня для усиления', '[{"he": "שָׁמוֹר תִּשְׁמֹר", "ru": "непременно сохрани", "translit": "шамОр тишмОр"}, {"he": "הָלוֹךְ הָלַךְ וְגָדֵל", "ru": "шёл и всё увеличивался", "translit": "hалОх hалАх ве-гадЕль"}]', '[{"text": "В современном разговорном иврите инфинитив абсолютный почти не используется, он сохраняется в юридических и литературных текстах"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (86, 117, 'Инфинитивные цепочки строятся последовательно: модальное слово + инф. + инф.', '[{"he": "אני רוצה להתחיל לעבוד", "ru": "Я хочу начать работать", "translit": "анИ роцЕ леhатхИль лаавОд"}, {"he": "צריך ללמוד לקרוא עברית", "ru": "Надо научиться читать на иврите", "translit": "царИх лильмОд ликрО иврИт"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (87, 117, 'Предлоги מבלי (без), תוך כדי (в процессе), במקום (вместо) сочетаются с инфинитивом', '[{"he": "הוא יצא מבלי לומר שלום", "ru": "Он вышел, не попрощавшись", "translit": "hу яцА мибли ломАр шалОм"}, {"he": "הוא עבד תוך כדי לימוד", "ru": "Он работал параллельно с учёбой", "translit": "hу авАд тох кдЕй лимУд"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (88, 118, 'Нифъаль может выражать четыре значения: пассив, рефлексив, медиальное и инхоативное (начало состояния)', '[{"he": "הספר נכתב (пассив)", "ru": "Книга была написана", "translit": "hа-сЕфер нихтАв"}, {"he": "הוא נרדם (инхоативное)", "ru": "Он заснул", "translit": "hу нирдАм"}, {"he": "הכוס נשברה (медиальное)", "ru": "Стакан разбился", "translit": "hа-кос нишберА"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (89, 118, 'В Хитпаэль с корнями на шипящие (ש, ס, צ) происходит метатеза: הת+ש → השת', '[{"he": "השתמש (а не *התשמש)", "ru": "использовал", "translit": "hиштамЕш"}, {"he": "הסתדר (а не *התסדר)", "ru": "устроился", "translit": "hистадЕр"}, {"he": "הצטלם (а не *התצלם)", "ru": "сфотографировался", "translit": "hицталЕм"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (90, 119, 'Академический иврит предпочитает именные конструкции глагольным: вместо «они исследовали» — «исследование (чего-то)»', '[{"he": "חקירת הנושא העלתה ממצאים חדשים", "ru": "Исследование темы выявило новые данные", "translit": "хакирАт hа-носЕ hеэлтА мимцаИм хадашИм"}, {"he": "התפתחות הילדים נבדקה", "ru": "Развитие детей было изучено", "translit": "hитпатхУт hа-еладИм нивдекА"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (91, 119, 'Безличные конструкции נמצא ש-, ניתן ל-, ראוי לציין используются для объективного изложения', '[{"he": "נמצא שהתופעה נפוצה", "ru": "Обнаружено, что явление распространено", "translit": "нимцА ше-hа-тофаА нефоцА"}, {"he": "ניתן להסיק מכך ש...", "ru": "Из этого можно заключить, что...", "translit": "нитАн леhасИк ми-кАх ше-"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (92, 120, 'Параллелизм — повторение структуры в двух полустишиях — основной приём библейской и современной поэзии', '[{"he": "השמים מספרים כבוד אל / ומעשה ידיו מגיד הרקיע", "ru": "Небеса рассказывают славу Бога / и дело рук Его возвещает небосвод", "translit": "hа-шамАйим месаперИм квод Эль / у-маасЕ ядАв магИд hа-ракИа"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (93, 120, 'Хиазм (перекрёстная структура A-B-B''-A'') создаёт эффект симметрии и завершённости', '[{"he": "אוכל לחם ומים שותה", "ru": "Ест хлеб и воду пьёт (глагол-объект / объект-глагол)", "translit": "охЕль лЕхем у-мАйим шотЕ"}, {"he": "ראשון לציון ואחרון לירושלים", "ru": "Первый для Сиона и последний для Иерусалима", "translit": "ришОн ле-цийОн ве-ахарОн ле-ерушалАйим"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (94, 121, 'Вав-последовательный (וַו הַהִפּוּךְ) в библейском иврите превращает будущее время в прошедшее повествование', '[{"he": "וַיֹּאמֶר (библейский) = הוא אמר (современный)", "ru": "и он сказал", "translit": "ваЙОмер = hу амАр"}, {"he": "וַיֵּלֶךְ (библейский) = הוא הלך (современный)", "ru": "и он пошёл", "translit": "ваЕлех = hу hалАх"}]', '[{"text": "В современном иврите вав-последовательный не используется продуктивно, но встречается в цитатах и идиомах"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (95, 121, 'Относительное местоимение אשר (библейский) заменено на ש- в современном иврите', '[{"he": "הדבר אשר אמרתי (библейский) = הדבר שאמרתי (современный)", "ru": "то, что я сказал", "translit": "hа-давАр ашЕр амАрти / ше-амАрти"}, {"he": "האיש אשר ראיתי (библейский) = האיש שראיתי (современный)", "ru": "мужчина, которого я видел", "translit": "hа-Иш ашЕр раИти / ше-раИти"}]', '[{"text": "אשר всё ещё используется в формальном и юридическом иврите"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (96, 122, 'Израильский стиль общения — дугри (прямолинейный), но смягчение достигается через косвенные конструкции', '[{"he": "אפשר לקבל מים? (вместо: תן לי מים)", "ru": "Можно получить воды? (вместо: Дай мне воды)", "translit": "эфшАр лекабЕль мАйим?"}, {"he": "אתה יכול לבוא לרגע? (вместо: בוא הנה)", "ru": "Ты можешь подойти на минуту? (вместо: Иди сюда)", "translit": "атА яхОль лавО ле-рЕга?"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (97, 122, 'Хеджирование — снижение категоричности — достигается словами כנראה, בערך, אולי, במידה מסוימת', '[{"he": "כנראה שהוא צודק", "ru": "По-видимому, он прав", "translit": "ке-нирЕ ше-hу цодЕк"}, {"he": "זה בערך חמישים שקלים", "ru": "Это примерно пятьдесят шекелей", "translit": "зэ бе-Эрех хамишИм шкалИм"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (98, 122, 'Дискурсные частицы (נו, יאללה, כבר, בקיצור) выполняют прагматические функции побуждения и резюмирования', '[{"he": "נו, אז מה החלטת?", "ru": "Ну, так что решил?", "translit": "ну, аз ма hехлАтта?"}, {"he": "בקיצור, לא הצלחנו", "ru": "Короче, у нас не получилось", "translit": "бе-кицУр, ло hицлАхну"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (99, 123, 'Высокий регистр маркируется словами אשר (а не ש-), אכן, בטרם, אף — и полными грамматическими формами', '[{"he": "אכן, הדבר אשר אמרתי נכון הוא", "ru": "Воистину, сказанное мною правильно", "translit": "ахЕн, hа-давАр ашЕр амАрти нахОн hу"}, {"he": "בטרם נפרד, אבקש לומר", "ru": "Прежде чем расстанемся, попрошу сказать", "translit": "бетЕрем нипарЕд, авакЕш ломАр"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (100, 123, 'Разговорный регистр и сленг маркируются сокращениями, арабскими заимствованиями и упрощённой грамматикой', '[{"he": "יאללה, ביי! (сленг)", "ru": "Ну, пока!", "translit": "ялла, бай!"}, {"he": "תכלס, זה לא משנה (разговорный)", "ru": "По существу, это неважно", "translit": "тахлЕс, зэ ло мешанЕ"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (101, 124, 'Четырёхбуквенные (квадрилитеральные) корни спрягаются по модели Пиэль: תִּרְגֵּם, טִלְפֵּן, שִׁכְפֵּל', '[{"he": "הוא תירגם את הספר", "ru": "Он перевёл книгу", "translit": "hу тиргЕм эт hа-сЕфер"}, {"he": "היא טלפנה אליו", "ru": "Она позвонила ему", "translit": "hи тильпенА элАв"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (102, 124, 'Мишкали מִקְטָל (инструмент), תַּקְטִיל (результат) и מַקְטֵלָה (устройство) продуктивно используются для создания новых слов', '[{"he": "מקלדת (מ.ק.ל.ד)", "ru": "клавиатура", "translit": "миклЕдет"}, {"he": "תקליט (ת.ק.ל.ט)", "ru": "пластинка, компакт-диск", "translit": "таклИт"}, {"he": "מחשב (מ.ח.ש.ב)", "ru": "компьютер", "translit": "махшЕв"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (103, 125, 'Средневековый иврит заимствовал из арабского абстрактную и философскую терминологию через кальки и семантические заимствования', '[{"he": "מָהוּת (от арабского māhiyya)", "ru": "сущность", "translit": "маhУт"}, {"he": "הַגְדָּרָה (калька с арабского taʿrīf)", "ru": "определение", "translit": "hагдарА"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (104, 125, 'Мелица (מליצה) — стилистический приём средневековой поэзии: использование библейского выражения в новом контексте', '[{"he": "\"ארץ זבת חלב ודבש\" (о цветущем саде)", "ru": "«земля, текущая молоком и мёдом» (не о Израиле, а о саде)", "translit": "Эрец завАт халАв у-двАш"}, {"he": "\"מגדל עוז\" (о возлюбленной)", "ru": "«крепкая башня» (не об укреплении, а о красоте)", "translit": "мигдАль оз"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (105, 126, 'Повышение регистра маркируется переходом на формальные союзы (לפיכך вместо אז), литературную лексику и полные формы', '[{"he": "לפיכך, ברצוני להציע... (формальный)", "ru": "Поэтому я хотел бы предложить...", "translit": "лефихАх, бирцонИ леhацИа..."}, {"he": "אז, מה דעתך? (разговорный)", "ru": "Ну и что ты думаешь?", "translit": "аз, ма даатхА?"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (106, 126, 'Понижение регистра используется для создания близости, юмора или контраста и маркируется сленгом и сокращениями', '[{"he": "אחרי הנאום הרשמי: \"יאללה, לאכול!\"", "ru": "После официальной речи: «Давайте есть!»", "translit": "ахарЕй hа-неУм hа-рашмИ: ялла, леехОль!"}, {"he": "בקיצור, תכלס, לא הבנתי כלום", "ru": "Короче, по сути, я ничего не понял", "translit": "бе-кицУр, тахлЕс, ло hевАнти клюм"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (107, 127, 'Юридический иврит использует архаичные союзы הואיל ו- (поскольку), בכפוף ל- (при условии), דהיינו (то есть)', '[{"he": "הואיל והתובע לא התייצב, התיק נסגר", "ru": "Поскольку истец не явился, дело закрыто", "translit": "hоИль ве-hа-товЕа ло hитъяцЕв, hа-тИк нисгАр"}, {"he": "בכפוף להוראות החוק", "ru": "При условии соблюдения закона", "translit": "бе-хафУф ле-hораОт hа-хок"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (108, 127, 'Пассивные конструкции доминируют в юридических текстах: הוחלט, נקבע, הוגש, נדחה', '[{"he": "הוחלט לדחות את הערעור", "ru": "Было решено отклонить апелляцию", "translit": "hухлАт лидхОт эт hа-ирУр"}, {"he": "נקבע כי התובע ישלם הוצאות", "ru": "Установлено, что истец оплатит расходы", "translit": "никбА ки hа-товЕа ешалЕм hоцаОт"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (109, 128, 'Библейская поэзия строится на ударном ритме (3+3, 3+2, 4+4), а не на силлабическом метре', '[{"he": "הַשָּׁמַיִם מְסַפְּרִים / כְּבוֹד אֵל (3+2)", "ru": "Небеса рассказывают / славу Бога", "translit": "hа-шамАйим месаперИм / квод Эль"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (110, 128, 'Корневая система иврита естественно создаёт аллитерацию и звукопись при повторении корней', '[{"he": "שִׁיר הַשִּׁירִים", "ru": "Песнь Песней (корень ש.י.ר дважды)", "translit": "шир hа-ширИм"}, {"he": "קוֹל קוֹרֵא בַּמִּדְבָּר", "ru": "Голос взывающий в пустыне (корень ק.ר.א)", "translit": "коль корЕ ба-мидбАр"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (111, 128, 'Поэтический синтаксис допускает свободную инверсию и эллипсис связки для создания ритма', '[{"he": "עָבַר הַקַּיִץ (инверсия: сказуемое-подлежащее)", "ru": "Прошло лето", "translit": "авАр hа-кАйиц"}, {"he": "הַלַּיְלָה — שָׁחוֹר (эллипсис связки)", "ru": "Ночь — чёрная", "translit": "hа-лАйла — шахОр"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (112, 129, 'Двойственное число (-ַיִם) сохраняется для парных органов тела и некоторых временных единиц', '[{"he": "יָדַיִם (а не *ידות)", "ru": "руки (две)", "translit": "ядАйим"}, {"he": "עֵינַיִם", "ru": "глаза (два)", "translit": "эйнАйим"}, {"he": "שְׁבוּעַיִם", "ru": "две недели", "translit": "швуАйим"}]', '[{"text": "Для чисел больше двух используется обычное множественное число: שלוש ידיים → שלוש ידיים (но это редко)"}]');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (113, 129, 'Парагогическое -ָה направления (hе-локатив) указывает направление движения и сохраняется в современных наречиях', '[{"he": "הַבַּיְתָה", "ru": "домой", "translit": "hа-бАйта"}, {"he": "צָפוֹנָה", "ru": "на север", "translit": "цафОна"}, {"he": "יְרוּשָׁלַיְמָה", "ru": "в Иерусалим", "translit": "ерушалАйма"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (114, 130, 'Интертекстуальность — отсылка к библейским и литературным текстам — пронизывает израильскую культуру и публицистику', '[{"he": "תוהו ובוהו (Быт. 1:2) = хаос", "ru": "Хаос, неразбериха (букв. «безвидна и пуста»)", "translit": "тОhу ва-вОhу"}, {"he": "ארץ זבת חלב ודבש = Израиль (идеализированный)", "ru": "Земля, текущая молоком и мёдом", "translit": "Эрец завАт халАв у-двАш"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (115, 130, 'Ирония достигается через литоту (לא רע = отлично), гиперболу (מת מצחוק) и контраст регистров', '[{"he": "\"לא רע\" (в значении «отлично»)", "ru": "Неплохо (= превосходно)", "translit": "ло ра"}, {"he": "\"מת על זה\" (в значении «обожаю»)", "ru": "Умираю от этого (= обожаю)", "translit": "мет аль зэ"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (116, 130, 'Каждый израильский писатель имеет узнаваемый стиль, определяемый соотношением регистров, длиной предложений и типом метафор', '[{"he": "שפת עמוס עוז: משפטים ארוכים, מטאפורות מדבריות", "ru": "Язык Амоса Оза: длинные предложения, метафоры пустыни", "translit": "сфат Амос Оз"}, {"he": "שפת אתגר קרת: משפטים קצרים, אבסורד", "ru": "Язык Этгара Керета: короткие предложения, абсурд", "translit": "сфат Этгар Керет"}]', NULL);
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (117, 4, 'Основные предлоги иврита: בְּ (в, внутри), לְ (к, для), מִ (из, от), עַל (на, о), עִם (с), אֶל (к), אֵצֶל (у, возле). Предлоги пишутся слитно с существительным: בַּבַּיִת = בְּ + הַבַּיִת.', '"[{\"he\": \"אני גר בְּתֵל אָבִיב\", \"ru\": \"Я живу в Тель-Авиве\", \"translit\": \"ани гар бе-тель авив\"}, {\"he\": \"הוא הולך לַעֲבוֹדָה\", \"ru\": \"Он идёт на работу\", \"translit\": \"ху холех ла-авода\"}, {\"he\": \"היא באה מֵהַבַּיִת\", \"ru\": \"Она пришла из дома\", \"translit\": \"хи баа ме-ха-байт\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (118, 4, 'Предлоги בְּ, לְ, מִ при присоединении к определённому артиклю הַ сливаются с ним: בְּ + הַ = בַּ, לְ + הַ = לַ, מִ + הַ = מֵהַ. Это важнейшее правило — предлог «поглощает» артикль.', '"[{\"he\": \"הילד בַּגָּן\", \"ru\": \"Ребёнок в саду (определённом)\", \"translit\": \"ха-йелед ба-ган\"}, {\"he\": \"אנחנו הולכים לַפַּארְק\", \"ru\": \"Мы идём в парк\", \"translit\": \"анахну холхим ла-парк\"}, {\"he\": \"הספר מֵהַסִּפְרִיָּה\", \"ru\": \"Книга из библиотеки\", \"translit\": \"ха-сефер ме-ха-сифрия\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (119, 4, 'Предлоги склоняются с местоимёнными суффиксами. Например: שֶׁלִּי (мой), שֶׁלְּךָ (твой м.), שֶׁלָּךְ (твой ж.), שֶׁלּוֹ (его), שֶׁלָּהּ (её), שֶׁלָּנוּ (наш), שֶׁלָּכֶם (ваш), שֶׁלָּהֶם (их).', '"[{\"he\": \"הספר שֶׁלִּי על השולחן\", \"ru\": \"Моя книга на столе\", \"translit\": \"ха-сефер шели аль ха-шульхан\"}, {\"he\": \"הבית שֶׁלָּנוּ גדול\", \"ru\": \"Наш дом большой\", \"translit\": \"ха-байт шелану гадоль\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (120, 6, 'Смихут (סְמִיכוּת) — это конструкция из двух существительных, где первое определяется вторым. Первое слово (נִסְמָךְ) стоит в сопряжённой форме, второе (סוֹמֵךְ) — в обычной. Порядок: определяемое + определяющее.', '"[{\"he\": \"בֵּית סֵפֶר\", \"ru\": \"школа (дом + книга)\", \"translit\": \"бейт сефер\"}, {\"he\": \"חֲדַר שֵׁנָה\", \"ru\": \"спальня (комната + сон)\", \"translit\": \"хадар шена\"}, {\"he\": \"בֵּית חוֹלִים\", \"ru\": \"больница (дом + больные)\", \"translit\": \"бейт холим\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (121, 6, 'В сопряжённой форме окончание -ִים меняется на -ֵי, а -ָה часто на -ַת. Артикль הַ ставится только перед вторым словом, а не перед первым. Прилагательное стоит после всей конструкции.', '"[{\"he\": \"חַדְרֵי הַמָּלוֹן\", \"ru\": \"комнаты отеля\", \"translit\": \"хадрей ха-малон\"}, {\"he\": \"תַּלְמִידַת הַכִּתָּה\", \"ru\": \"ученица класса\", \"translit\": \"тальмидат ха-кита\"}, {\"he\": \"בֵּית הַסֵּפֶר הַגָּדוֹל\", \"ru\": \"большая школа\", \"translit\": \"бейт ха-сефер ха-гадоль\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (122, 40, 'Слово יֵשׁ означает «есть, имеется». Для обладания используется конструкция יֵשׁ לִי (у меня есть). Отрицание — אֵין לִי (у меня нет). Эти слова не изменяются по лицам и числам.', '"[{\"he\": \"יֵשׁ לִי חתול\", \"ru\": \"У меня есть кот\", \"translit\": \"йеш ли хатуль\"}, {\"he\": \"אֵין לָהּ זמן\", \"ru\": \"У неё нет времени\", \"translit\": \"эйн ла заман\"}, {\"he\": \"יֵשׁ פה בית קפה?\", \"ru\": \"Здесь есть кафе?\", \"translit\": \"йеш по бейт кафе?\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (123, 40, 'יֵשׁ/אֵין также используются для описания существования: יֵשׁ בְּעָיָה (есть проблема), אֵין מָקוֹם (нет места). С предлогами: יֵשׁ לְ (у кого-то есть), יֵשׁ בְּ (в чём-то есть), אֵין מִ (не из чего).', '"[{\"he\": \"יֵשׁ הרבה אנשים ברחוב\", \"ru\": \"На улице много людей\", \"translit\": \"йеш харбэ анашим ба-рехов\"}, {\"he\": \"אֵין חלב בַּמִּקְרָר\", \"ru\": \"В холодильнике нет молока\", \"translit\": \"эйн халав ба-микрар\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (124, 41, 'Прилагательное в иврите стоит ПОСЛЕ существительного и согласуется с ним в роде, числе и определённости. Если существительное с артиклем הַ, то и прилагательное получает הַ.', '"[{\"he\": \"ילד טוב\", \"ru\": \"хороший мальчик\", \"translit\": \"йелед тов\"}, {\"he\": \"ילדה טובה\", \"ru\": \"хорошая девочка\", \"translit\": \"ялда това\"}, {\"he\": \"הַיֶּלֶד הַטּוֹב\", \"ru\": \"хороший мальчик (определённый)\", \"translit\": \"ха-йелед ха-тов\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (125, 41, 'Множественное число прилагательных: м.р. + -ִים, ж.р. + -וֹת. Прилагательное на -ִי (типа יִשְׂרְאֵלִי) в ж.р. → -ִית, во мн.ч. м.р. → -ִיִּים, мн.ч. ж.р. → -ִיּוֹת.', '"[{\"he\": \"ילדים טובים\", \"ru\": \"хорошие мальчики\", \"translit\": \"йеладим товим\"}, {\"he\": \"ילדות טובות\", \"ru\": \"хорошие девочки\", \"translit\": \"йеладот товот\"}, {\"he\": \"שיר יִשְׂרְאֵלִי / שירים יִשְׂרְאֵלִיִּים\", \"ru\": \"израильская песня / израильские песни\", \"translit\": \"шир исраэли / ширим исраэлиим\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (126, 44, 'Наречия в иврите не изменяются. Наречия времени: עַכְשָׁו (сейчас), הַיּוֹם (сегодня), אֶתְמוֹל (вчера), מָחָר (завтра), תָּמִיד (всегда), אַף פַּעַם (никогда). Наречия места: פֹּה/כָּאן (здесь), שָׁם (там), בַּחוּץ (снаружи), בִּפְנִים (внутри).', '"[{\"he\": \"אני עכשיו בבית\", \"ru\": \"Я сейчас дома\", \"translit\": \"ани ахшав ба-байт\"}, {\"he\": \"הוא תמיד מגיע בזמן\", \"ru\": \"Он всегда приходит вовремя\", \"translit\": \"ху тамид магиа ба-зман\"}, {\"he\": \"אתמול היה גשם\", \"ru\": \"Вчера был дождь\", \"translit\": \"этмоль хая гешем\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (127, 44, 'Наречия образа действия: מַהֵר (быстро), לְאַט (медленно), טוֹב (хорошо), רַע (плохо), הַרְבֵּה (много), קְצָת (немного), מְאוֹד (очень). Наречие обычно стоит после глагола.', '"[{\"he\": \"הוא רץ מהר\", \"ru\": \"Он бежит быстро\", \"translit\": \"ху рац маhер\"}, {\"he\": \"אני מדבר עברית קצת\", \"ru\": \"Я немного говорю на иврите\", \"translit\": \"ани медабер иврит кцат\"}, {\"he\": \"היא שרה טוב מאוד\", \"ru\": \"Она поёт очень хорошо\", \"translit\": \"хи шара тов меод\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (128, 45, 'В иврите нет глагола «быть» в настоящем времени. Именное предложение строится по схеме: подлежащее + сказуемое. Местоимение הוּא/הִיא/הֵם/הֵן может выступать связкой между подлежащим и именным сказуемым.', '"[{\"he\": \"דני מורה\", \"ru\": \"Дани — учитель\", \"translit\": \"дани морэ\"}, {\"he\": \"הספר הזה טוב\", \"ru\": \"Эта книга хорошая\", \"translit\": \"ха-сефер ха-зэ тов\"}, {\"he\": \"ירושלים היא עיר עתיקה\", \"ru\": \"Иерусалим — древний город\", \"translit\": \"йерушалаим хи ир атика\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (129, 45, 'Вопрос «Кто это?» / «Что это?» строится как מִי זֶה? / מָה זֶה? Ответ: זֶה + существительное (м.р.) или זֹאת + существительное (ж.р.). Во множественном числе — אֵלֶּה.', '"[{\"he\": \"מה זה? — זה ספר\", \"ru\": \"Что это? — Это книга\", \"translit\": \"ма зэ? — зэ сефер\"}, {\"he\": \"מי זאת? — זאת המורה שלי\", \"ru\": \"Кто это? — Это моя учительница\", \"translit\": \"ми зот? — зот ха-мора шели\"}, {\"he\": \"מה אלה? — אלה תפוחים\", \"ru\": \"Что это? — Это яблоки\", \"translit\": \"ма элэ? — элэ тапухим\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (130, 46, 'Базовый порядок слов в иврите: подлежащее — сказуемое — дополнение (SVO). Прямое дополнение определённое вводится частицей אֶת: אני רואה אֶת הילד (я вижу мальчика). Без הַ частица אֶת не нужна.', '"[{\"he\": \"אני אוכל תפוח\", \"ru\": \"Я ем яблоко (неопр.)\", \"translit\": \"ани охель тапуах\"}, {\"he\": \"אני אוכל אֶת הַתַּפּוּחַ\", \"ru\": \"Я ем (это) яблоко (опр.)\", \"translit\": \"ани охель эт ха-тапуах\"}, {\"he\": \"היא קוראת אֶת הַסֵּפֶר\", \"ru\": \"Она читает (эту) книгу\", \"translit\": \"хи корэт эт ха-сефер\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (131, 46, 'Обстоятельства времени обычно стоят в начале или в конце предложения. Отрицание לֹא стоит прямо перед глаголом. Вопрос без вопросительного слова строится интонацией (или с הַאִם в формальном стиле).', '"[{\"he\": \"בבוקר אני שותה קפה\", \"ru\": \"Утром я пью кофе\", \"translit\": \"ба-бокер ани шотэ кафе\"}, {\"he\": \"אני לֹא מבין\", \"ru\": \"Я не понимаю\", \"translit\": \"ани ло мевин\"}, {\"he\": \"אתה רוצה קפה?\", \"ru\": \"Ты хочешь кофе?\", \"translit\": \"ата роцэ кафе?\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (132, 7, 'В иврите 7 биньянов (глагольных моделей): פָּעַל (Пааль) — простое активное, נִפְעַל (Нифъаль) — пассив/возвратное, פִּעֵל (Пиэль) — интенсив/каузатив, פֻּעַל (Пуаль) — пассив от Пиэля, הִפְעִיל (Хифъиль) — каузатив, הוּפְעַל (Хуфъаль) — пассив от Хифъиля, הִתְפַּעֵל (Хитпаэль) — возвратное/взаимное.', '"[{\"he\": \"הוא כָּתַב מכתב\", \"ru\": \"Он написал письмо (Пааль — простое действие)\", \"translit\": \"ху катав михтав\"}, {\"he\": \"המכתב נִכְתַּב אתמול\", \"ru\": \"Письмо было написано вчера (Нифъаль — пассив)\", \"translit\": \"ха-михтав нихтав этмоль\"}, {\"he\": \"הוא הִתְלַבֵּשׁ מהר\", \"ru\": \"Он быстро оделся (Хитпаэль — возвратное)\", \"translit\": \"ху хитлабеш маhер\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (133, 7, 'Один и тот же корень в разных биньянах даёт разные, но связанные значения. Например, корень ל.מ.ד: לָמַד (учился, Пааль), לִמֵּד (преподавал, Пиэль), הִתְלַמֵּד (обучался самостоятельно, Хитпаэль). Корень определяет базовый смысл, а биньян — тип действия.', '"[{\"he\": \"הוא לָמַד עברית\", \"ru\": \"Он учил иврит (Пааль)\", \"translit\": \"ху ламад иврит\"}, {\"he\": \"היא לִמְּדָה אותנו עברית\", \"ru\": \"Она преподавала нам иврит (Пиэль)\", \"translit\": \"хи лимда отану иврит\"}, {\"he\": \"הוא הִזְכִּיר לי\", \"ru\": \"Он напомнил мне (Хифъиль, корень ז.כ.ר)\", \"translit\": \"ху хизкир ли\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (134, 10, 'Повелительное наклонение (ציווי) образуется от будущего времени отбрасыванием приставки. Формы: м.р. ед.ч. — כְּתֹב (ктов), ж.р. ед.ч. — כִּתְבִי (китви), мн.ч. — כִּתְבוּ (китву). В разговорном иврите часто используется будущее время вместо императива.', '"[{\"he\": \"!כְּתֹב את השם שלך\", \"ru\": \"Напиши своё имя! (м.р.)\", \"translit\": \"ктов эт ха-шем шелха!\"}, {\"he\": \"!שִׁבְי כאן\", \"ru\": \"Сядь здесь! (ж.р.)\", \"translit\": \"шви кан!\"}, {\"he\": \"!בּוֹאוּ הנה\", \"ru\": \"Идите сюда! (мн.ч.)\", \"translit\": \"боу hена!\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (135, 10, 'Отрицательный императив образуется с помощью אַל + будущее время (НЕ לא!). Вежливые просьбы используют בְּבַקָּשָׁה (пожалуйста) или будущее время с вопросительной интонацией: תוכל לעזור לי? (Можешь помочь мне?).', '"[{\"he\": \"!אַל תִּכְתֹּב על הקיר\", \"ru\": \"Не пиши на стене!\", \"translit\": \"аль тихтов аль ха-кир!\"}, {\"he\": \"!אַל תִּדְאַג\", \"ru\": \"Не волнуйся!\", \"translit\": \"аль тидаг!\"}, {\"he\": \"שב בבקשה\", \"ru\": \"Сядь, пожалуйста\", \"translit\": \"шев бевакаша\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (136, 12, 'Сравнительная степень: יוֹתֵר (йотер, более) + прилагательное + מִ (ми, чем). Превосходная степень: הֲכִי (hахи, самый) + прилагательное. Альтернатива для превосходной: הַ + прилагательное + בְּיוֹתֵר (бейотер).', '"[{\"he\": \"הבית הזה יוֹתֵר גדול מֵהַבַּיִת שלי\", \"ru\": \"Этот дом больше моего дома\", \"translit\": \"ха-байт ха-зэ йотер гадоль ме-ха-байт шели\"}, {\"he\": \"היא הֲכִי חכמה בכיתה\", \"ru\": \"Она самая умная в классе\", \"translit\": \"хи hахи хахама ба-кита\"}, {\"he\": \"זה המסעדה הטובה בְּיוֹתֵר בעיר\", \"ru\": \"Это лучший ресторан в городе\", \"translit\": \"зэ ха-мисада ха-това бейотер ба-ир\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (137, 12, 'Некоторые прилагательные имеют нерегулярные формы сравнения: טוֹב (хороший) → יוֹתֵר טוֹב (лучше) → הֲכִי טוֹב (лучший). רַע (плохой) → יוֹתֵר גָּרוּעַ (хуже) → הֲכִי גָּרוּעַ (худший). הַרְבֵּה (много) → יוֹתֵר (больше) → הֲכִי הַרְבֵּה (больше всего).', '"[{\"he\": \"הסרט הזה יוֹתֵר טוֹב מהספר\", \"ru\": \"Этот фильм лучше книги\", \"translit\": \"ха-серет ха-зэ йотер тов ме-ха-сефер\"}, {\"he\": \"היום הֲכִי גָּרוּעַ בחיים שלי\", \"ru\": \"Худший день в моей жизни\", \"translit\": \"ха-йом hахи гаруа ба-хаим шели\"}, {\"he\": \"מי רץ יוֹתֵר מהר?\", \"ru\": \"Кто бежит быстрее?\", \"translit\": \"ми рац йотер маhер?\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (138, 47, 'Частица אֶת (эт) ставится перед определённым прямым дополнением: перед существительными с артиклем הַ, именами собственными и местоимениями. Без определённости אֶת не нужна: אני רואה ילד (вижу мальчика) vs. אני רואה את הילד (вижу этого мальчика).', '"[{\"he\": \"אני רואה אֶת הַיֶּלֶד\", \"ru\": \"Я вижу (этого) мальчика\", \"translit\": \"ани роэ эт ха-йелед\"}, {\"he\": \"הוא אוהב אֶת שרה\", \"ru\": \"Он любит Сару\", \"translit\": \"ху оhев эт Сара\"}, {\"he\": \"אני קורא ספר\", \"ru\": \"Я читаю (какую-то) книгу (без את)\", \"translit\": \"ани корэ сефер\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (139, 47, 'אֶת с местоимёнными суффиксами: אוֹתִי (меня), אוֹתְךָ (тебя, м.), אוֹתָךְ (тебя, ж.), אוֹתוֹ (его), אוֹתָהּ (её), אוֹתָנוּ (нас), אוֹתְכֶם (вас, м.), אוֹתְכֶן (вас, ж.), אוֹתָם (их, м.), אוֹתָן (их, ж.).', '"[{\"he\": \"היא רואה אוֹתִי\", \"ru\": \"Она видит меня\", \"translit\": \"хи роа оти\"}, {\"he\": \"אני אוהב אוֹתָךְ\", \"ru\": \"Я люблю тебя (ж.)\", \"translit\": \"ани оhев отах\"}, {\"he\": \"הם מחכים לנו, הם רוצים אוֹתָנוּ\", \"ru\": \"Они ждут нас, они хотят нас\", \"translit\": \"hем мехаким лану, hем роцим отану\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (140, 48, 'Сочинительные союзы: וְ (ве, и) — пишется слитно с первой буквой следующего слова, אוֹ (о, или), אֲבָל (аваль, но), אֶלָּא (эла, но/а — после отрицания). Союз וְ перед буквами בומ"פ читается как «у»: וּבַבַּיִת.', '"[{\"he\": \"אני לומד עברית וְעַרָבִית\", \"ru\": \"Я учу иврит и арабский\", \"translit\": \"ани ломед иврит ве-аравит\"}, {\"he\": \"אתה רוצה תה אוֹ קפה?\", \"ru\": \"Ты хочешь чай или кофе?\", \"translit\": \"ата роцэ тэ о кафе?\"}, {\"he\": \"הוא לא עייף אֶלָּא רעב\", \"ru\": \"Он не уставший, а голодный\", \"translit\": \"ху ло аеф эла раэв\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (141, 48, 'Подчинительные союзы: כִּי / מִכֵּיוָן שֶׁ (ки / микейван ше, потому что), כְּשֶׁ (кше, когда), אִם (им, если), לִפְנֵי שֶׁ (лифней ше, до того как), אַחֲרֵי שֶׁ (ахарей ше, после того как), בִּזְמַן שֶׁ (бизман ше, в то время как).', '"[{\"he\": \"אני שמח כִּי אתה כאן\", \"ru\": \"Я рад, потому что ты здесь\", \"translit\": \"ани самеах ки ата кан\"}, {\"he\": \"כְּשֶׁהגעתי הביתה, ירד גשם\", \"ru\": \"Когда я пришёл домой, пошёл дождь\", \"translit\": \"кше-hигати ха-байта, ярад гешем\"}, {\"he\": \"אִם תרצה, נלך לסרט\", \"ru\": \"Если захочешь, пойдём в кино\", \"translit\": \"им тирцэ, нелех ле-серет\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (142, 50, 'Биньян Нифъаль (נִפְעַל) образуется добавлением נִ перед корнем. Выражает пассив или возвратное значение. Настоящее: נִפְעָל (нифъаль), прошедшее: נִפְעַלְתִּי (нифъальти), будущее: אֶפָּעֵל (эпаэль). Инфинитив: לְהִפָּעֵל (леhипаэль).', '"[{\"he\": \"הדלת נִפְתְּחָה\", \"ru\": \"Дверь открылась (пассив/возвратное)\", \"translit\": \"ха-делет нифтеха\"}, {\"he\": \"הוא נִכְנַס לחדר\", \"ru\": \"Он вошёл в комнату\", \"translit\": \"ху нихнас ла-хедер\"}, {\"he\": \"התינוק נוֹלַד בבוקר\", \"ru\": \"Ребёнок родился утром\", \"translit\": \"ха-тинок нолад ба-бокер\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (143, 50, 'Частые глаголы Нифъаля: נִכְנַס (вошёл), נִשְׁאַר (остался), נוֹלַד (родился), נִפְתַּח (открылся), נִסְגַּר (закрылся), נֶהֱנָה (наслаждался), נִזְכַּר (вспомнил), נִפְגַּשׁ (встретился). Многие из них потеряли пассивное значение и стали самостоятельными глаголами.', '"[{\"he\": \"הוא נִשְׁאַר בבית\", \"ru\": \"Он остался дома\", \"translit\": \"ху нишар ба-байт\"}, {\"he\": \"החנות נִסְגְּרָה מוקדם\", \"ru\": \"Магазин закрылся рано\", \"translit\": \"ха-ханут нисгера мукдам\"}, {\"he\": \"אנחנו נִפְגַּשְׁנוּ במקרה\", \"ru\": \"Мы встретились случайно\", \"translit\": \"анахну нифгашну бемикрэ\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (144, 51, 'Пуаль (פֻּעַל) — пассив от Пиэля. Шаблон: קֻטַּל. Прошедшее: קֻטַּלְתִּי, настоящее: מְקֻטָּל, будущее: אֲקֻטַּל. Нет формы императива и инфинитива. Используется преимущественно в формальной речи и прессе.', '"[{\"he\": \"הסרט צֻלַּם בירושלים\", \"ru\": \"Фильм был снят в Иерусалиме\", \"translit\": \"ха-серет цулам бирушалаим\"}, {\"he\": \"הספר תֻּרְגַּם לעברית\", \"ru\": \"Книга была переведена на иврит\", \"translit\": \"ха-сефер тургам ле-иврит\"}, {\"he\": \"הילד בּוּרַךְ על ידי הרב\", \"ru\": \"Ребёнок был благословлён раввином\", \"translit\": \"ха-йелед борах аль йедей ха-рав\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (145, 51, 'Хуфъаль (הוּפְעַל) — пассив от Хифъиля. Шаблон: הוּקְטַל. Прошедшее: הוּקְטַלְתִּי, настоящее: מוּקְטָל, будущее: אוּקְטַל. Как и Пуаль, не имеет императива и инфинитива. Встречается реже всех биньянов.', '"[{\"he\": \"הוא הוּזְמַן לחתונה\", \"ru\": \"Он был приглашён на свадьбу\", \"translit\": \"ху hузман ла-хатуна\"}, {\"he\": \"המשחק הוּפְסַק בגלל גשם\", \"ru\": \"Игра была остановлена из-за дождя\", \"translit\": \"ха-мисхак hуфсак бигляль гешем\"}, {\"he\": \"השיעור הוּקְלַט\", \"ru\": \"Урок был записан\", \"translit\": \"ха-шиур hуклат\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (146, 52, 'Биньян Хитпаэль (הִתְפַּעֵל) образуется добавлением הִתְ перед корнем. Выражает возвратное, взаимное или «срединное» действие. Настоящее: מִתְפַּעֵל (митпаэль), прошедшее: הִתְפַּעַלְתִּי (хитпаальти), будущее: אֶתְפַּעֵל (этпаэль).', '"[{\"he\": \"אני מִתְלַבֵּשׁ\", \"ru\": \"Я одеваюсь (возвратное)\", \"translit\": \"ани митлабеш\"}, {\"he\": \"הם הִתְחַתְּנוּ בקיץ\", \"ru\": \"Они поженились летом (взаимное)\", \"translit\": \"hем хитхатну ба-каиц\"}, {\"he\": \"היא מִתְרַגֶּשֶׁת מהסרט\", \"ru\": \"Она волнуется от фильма (эмоц. состояние)\", \"translit\": \"хи митрагешет ме-ха-серет\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (147, 52, 'Правило метатезы: когда корень начинается с צ, ס или שׁ, буква ת меняется местами с первой буквой корня. Пример: корень ס.ד.ר → הִסְתַּדֵּר (устроился), а не *הִתְסַדֵּר. При корне на ד, ט или ת буква ת ассимилируется: корень ד.ב.ר → הִדַּבֵּר (разговаривал), не *הִתְדַבֵּר.', '"[{\"he\": \"הוא הִסְתַּדֵּר בעבודה חדשה\", \"ru\": \"Он устроился на новую работу (метатеза: ס↔ת)\", \"translit\": \"ху hистадер ба-авода хадаша\"}, {\"he\": \"הם הִצְטַלְּמוּ ביחד\", \"ru\": \"Они сфотографировались вместе (метатеза: צ↔ת)\", \"translit\": \"hем hицталму бейахад\"}, {\"he\": \"היא הִשְׁתַּמְּשָׁה במחשב\", \"ru\": \"Она воспользовалась компьютером (метатеза: שׁ↔ת)\", \"translit\": \"хи хиштамша ба-махшев\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (148, 53, 'Числа 11-19 образуются сочетанием единиц + עָשָׂר (м.р.) / עֶשְׂרֵה (ж.р.). Десятки: עֶשְׂרִים (20), שְׁלוֹשִׁים (30), אַרְבָּעִים (40), חֲמִשִּׁים (50), שִׁשִּׁים (60), שִׁבְעִים (70), שְׁמוֹנִים (80), תִּשְׁעִים (90). Десятки одинаковы для обоих родов.', '"[{\"he\": \"יש לי שְׁלוֹשָׁה עָשָׂר ספרים\", \"ru\": \"У меня тринадцать книг (м.р.)\", \"translit\": \"йеш ли шлоша асар сфарим\"}, {\"he\": \"היא בת אַרְבַּע עֶשְׂרֵה\", \"ru\": \"Ей четырнадцать лет (ж.р.)\", \"translit\": \"хи бат арба эсрэ\"}, {\"he\": \"בכיתה יש עֶשְׂרִים וְחָמֵשׁ תלמידות\", \"ru\": \"В классе двадцать пять учениц\", \"translit\": \"ба-кита йеш эсрим ве-хамеш тальмидот\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (149, 53, 'Порядковые числительные: רִאשׁוֹן (первый), שֵׁנִי (второй), שְׁלִישִׁי (третий), רְבִיעִי (четвёртый), חֲמִישִׁי (пятый), שִׁשִּׁי (шестой), שְׁבִיעִי (седьмой), שְׁמִינִי (восьмой), תְּשִׁיעִי (девятый), עֲשִׂירִי (десятый). Согласуются в роде: ж.р. → רִאשׁוֹנָה, שְׁנִיָּה и т.д.', '"[{\"he\": \"זאת הפעם הָרִאשׁוֹנָה שלי\", \"ru\": \"Это мой первый раз (ж.р.)\", \"translit\": \"зот ха-паам ха-ришона шели\"}, {\"he\": \"הוא גר בקומה הַשְּׁלִישִׁית\", \"ru\": \"Он живёт на третьем этаже\", \"translit\": \"ху гар ба-кома ха-шлишит\"}, {\"he\": \"יום שִׁשִּׁי — ערב שבת\", \"ru\": \"Пятница (шестой день) — канун субботы\", \"translit\": \"йом шиши — эрев шабат\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (150, 54, 'Основные частицы: גַּם (гам, тоже/также), רַק (рак, только), כְּבָר (квар, уже), עוֹד (од, ещё/всё ещё), אוּלַי (улай, может быть), דַּוְקָא (давка, именно/как раз), בִּכְלָל (бихлаль, вообще). Частицы обычно стоят перед словом, которое они подчёркивают.', '"[{\"he\": \"גַּם אני רוצה ללכת\", \"ru\": \"Я тоже хочу пойти\", \"translit\": \"гам ани роцэ лалехет\"}, {\"he\": \"הוא כְּבָר הגיע\", \"ru\": \"Он уже приехал\", \"translit\": \"ху квар hигиа\"}, {\"he\": \"אוּלַי נלך מחר?\", \"ru\": \"Может быть, пойдём завтра?\", \"translit\": \"улай нелех махар?\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (151, 54, 'Междометия и восклицания: !חֲבָל (хаваль, жаль!), !יַאללָה (яла, давай!/пошли!), !סַבָּבָה (сабаба, классно!/ок!), !אוֹי (ой, ох!), !וַואוּ (вау, вау!), !בְּחַיַּי (бехаяй, клянусь жизнью!). Широко используются в разговорном иврите.', '"[{\"he\": \"!חֲבָל שלא באת\", \"ru\": \"Жаль, что ты не пришёл!\", \"translit\": \"хаваль ше-ло бата!\"}, {\"he\": \"!יַאללָה, בואו נלך\", \"ru\": \"Давайте, пойдём!\", \"translit\": \"яла, боу нелех!\"}, {\"he\": \"?סַבָּבָה, נתראה מחר\", \"ru\": \"Окей, увидимся завтра?\", \"translit\": \"сабаба, нитраэ махар?\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (152, 55, 'Частица שֶׁ (ше) заменяет формальное אֲשֶׁר (ашер) в разговорной речи. Используется для: относительных придаточных (הספר שקראתי — книга, которую я читал), дополнительных придаточных (אני חושב שהוא צודק — я думаю, что он прав), временных (כשהגעתי — когда я прибыл).', '"[{\"he\": \"הספר שֶׁקָּרָאתִי היה מעניין\", \"ru\": \"Книга, которую я читал, была интересной\", \"translit\": \"ха-сефер ше-карати хая меаньен\"}, {\"he\": \"אני יודע שֶׁהוּא בבית\", \"ru\": \"Я знаю, что он дома\", \"translit\": \"ани йодеа ше-ху ба-байт\"}, {\"he\": \"כְּשֶׁיָּרַד גשם, נשארנו בבית\", \"ru\": \"Когда пошёл дождь, мы остались дома\", \"translit\": \"кше-ярад гешем, нишарну ба-байт\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (153, 55, 'שֶׁ с предлогами образует сложные относительные конструкции: שֶׁבּוֹ (в котором), שֶׁלּוֹ (которого/чей), שֶׁאֶצְלוֹ (у которого), שֶׁעָלָיו (о котором). В разговорной речи предлог часто выносится в конец: האיש שדיברתי איתו (человек, с которым я говорил).', '"[{\"he\": \"העיר שֶׁבָּהּ גרתי\", \"ru\": \"Город, в котором я жил\", \"translit\": \"ха-ир ше-ба гарти\"}, {\"he\": \"הבחור שֶׁדִּבַּרְתִּי אִתּוֹ\", \"ru\": \"Парень, с которым я разговаривал\", \"translit\": \"ха-бахур ше-дибарти ито\"}, {\"he\": \"מישהו שֶׁאֲנִי מַכִּיר\", \"ru\": \"Кто-то, кого я знаю\", \"translit\": \"мишеhу ше-ани макир\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (154, 56, 'Глаголы в иврите требуют определённых предлогов (как и в русском языке, но не всегда совпадающих). Основные сочетания: חוֹשֵׁב עַל (думает о), מְדַבֵּר עִם (разговаривает с), מְחַכֶּה לְ (ждёт кого/чего), דּוֹאֵג לְ (заботится о), שַׂמֵּחַ עַל (рад чему-то).', '"[{\"he\": \"אני חוֹשֵׁב עַל הבחינה\", \"ru\": \"Я думаю об экзамене\", \"translit\": \"ани хошев аль ха-бхина\"}, {\"he\": \"היא מְדַבֶּרֶת עִם חברה\", \"ru\": \"Она разговаривает с подругой\", \"translit\": \"хи медаберет им хавера\"}, {\"he\": \"אנחנו מְחַכִּים לָאוֹטוֹבּוּס\", \"ru\": \"Мы ждём автобус\", \"translit\": \"анахну мехаким ла-отобус\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (155, 56, 'Некоторые глаголы меняют значение в зависимости от предлога: עָלָה עַל (поднялся на / напал на), עָלָה לְ (стоил / поехал в Израиль), יָרַד מִ (спустился с), יָרַד לְ (понял смысл / уехал из Израиля). Предлоги нужно заучивать вместе с глаголами.', '"[{\"he\": \"הוא עָלָה עַל ההר\", \"ru\": \"Он поднялся на гору\", \"translit\": \"ху ала аль ха-hар\"}, {\"he\": \"היא עָלְתָה לְיִשְׂרָאֵל\", \"ru\": \"Она репатриировалась в Израиль\", \"translit\": \"хи алта ле-исраэль\"}, {\"he\": \"אני לא יָרַדְתִּי לְמָה שאמרת\", \"ru\": \"Я не понял, что ты сказал\", \"translit\": \"ани ло ярадти ле-ма ше-амарта\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (156, 57, 'Сравнительная степень образуется с помощью יוֹתֵר...מִ (более...чем) и פָּחוֹת...מִ (менее...чем). Структура: подлежащее + прилагательное + יותר/פחות + מ + объект сравнения. Предлог מ пишется слитно с определённым артиклем: מֵהַ.', '"[{\"he\": \"הדירה שלנו יותר גדולה מהדירה שלהם\", \"ru\": \"Наша квартира больше, чем их квартира\", \"translit\": \"ха-дира шелану йотер гдола ме-ха-дира шелаhем\"}, {\"he\": \"הבחינה הייתה פחות קשה ממה שחשבתי\", \"ru\": \"Экзамен был менее сложным, чем я думал\", \"translit\": \"ха-бхина hайта пахот каша мима ше-хашавти\"}, {\"he\": \"החורף בחיפה יותר חם מבירושלים\", \"ru\": \"Зима в Хайфе теплее, чем в Иерусалиме\", \"translit\": \"ха-хорев бе-хейфа йотер хам ми-бирушалаим\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (157, 57, 'Равенство выражается с помощью כְּמוֹ (как), בְּאוֹתָהּ מִידָה (в той же мере). Превосходная степень: הֲכִי + прилагательное (разг.) или הַ + прилагательное + בְּיוֹתֵר (формально). Обе формы широко используются.', '"[{\"he\": \"היא שרה יפה כמו אמא שלה\", \"ru\": \"Она поёт красиво, как её мама\", \"translit\": \"хи шара яфе кмо има шела\"}, {\"he\": \"זה הספר הכי מעניין שקראתי השנה\", \"ru\": \"Это самая интересная книга, которую я прочитал в этом году\", \"translit\": \"зэ ха-сефер hахи меаньен ше-карати ха-шана\"}, {\"he\": \"הוא הסטודנט המוצלח ביותר בקורס\", \"ru\": \"Он самый успешный студент на курсе\", \"translit\": \"ху ха-студент ха-муцлах бейотер ба-курс\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (158, 58, 'Причина выражается союзами: כִּי (потому что), מִכֵּיוָן שֶׁ (так как, формально), בִּגְלַל שֶׁ (из-за того что), הוֹאִיל וְ (поскольку, книжн.). Различие: בִּגְלַל + существительное (בגלל הגשם — из-за дождя) vs. בִּגְלַל שֶׁ + придаточное (בגלל שירד גשם — из-за того что пошёл дождь).', '"[{\"he\": \"לא באתי כי הייתי חולה\", \"ru\": \"Я не пришёл, потому что был болен\", \"translit\": \"ло бати ки hаити холе\"}, {\"he\": \"מכיוון שהמבחן קשה, צריך ללמוד הרבה\", \"ru\": \"Так как экзамен сложный, нужно много учиться\", \"translit\": \"микейван ше-ха-мивхан каше, царих лильмод hарбэ\"}, {\"he\": \"הטיול בוטל בגלל מזג האוויר\", \"ru\": \"Поездка была отменена из-за погоды\", \"translit\": \"ха-тиюль буталь бигляль мезег ха-авир\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (159, 58, 'Результат/следствие выражается словами: לָכֵן (поэтому), עַל כֵּן (поэтому, формально), כְּתוֹצָאָה מִכָּךְ (в результате этого), מִשּׁוּם כָּךְ (из-за этого). לכן — самое употребительное в разговорной речи; על כן, כתוצאה מכך — в письменной и официальной речи.', '"[{\"he\": \"ירד גשם חזק, לכן נשארנו בבית\", \"ru\": \"Пошёл сильный дождь, поэтому мы остались дома\", \"translit\": \"ярад гешем хазак, лахен нишарну ба-байт\"}, {\"he\": \"הוא עבד קשה מאוד, ועל כן קיבל העלאה\", \"ru\": \"Он очень усердно работал, и поэтому получил повышение\", \"translit\": \"ху авад каше меод, ве-аль кен кибель hаалаа\"}, {\"he\": \"כתוצאה מכך, המחירים עלו\", \"ru\": \"В результате этого цены выросли\", \"translit\": \"ке-тоцаа ми-ках, ха-мехирим алу\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (160, 59, 'Уступительные союзы: לַמְרוֹת שֶׁ / אַף עַל פִּי שֶׁ / עַל אַף שֶׁ (хотя/несмотря на то что). Различие: לַמְרוֹת + существительное (למרות הקושי — несмотря на трудность) vs. לַמְרוֹת שֶׁ + придаточное (למרות שזה קשה — хотя это трудно).', '"[{\"he\": \"למרות שהיה קר, יצאנו לטיול\", \"ru\": \"Хотя было холодно, мы пошли на прогулку\", \"translit\": \"ламрот ше-hая кар, яцану ле-тиюль\"}, {\"he\": \"אף על פי שהוא עייף, הוא המשיך לעבוד\", \"ru\": \"Хотя он устал, он продолжил работать\", \"translit\": \"аф аль пи ше-ху аеф, ху hимших лаавод\"}, {\"he\": \"על אף הקשיים, הם הצליחו\", \"ru\": \"Несмотря на трудности, они преуспели\", \"translit\": \"аль аф ха-кшаим, hем hицлиху\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (161, 59, 'Контрастные наречия во втором предложении: בְּכָל זֹאת (тем не менее), עִם זֹאת (вместе с тем), וּבְכָל אוֹפֶן (и в любом случае). Используются для выражения контраста: первая часть — уступка, вторая — неожиданный результат.', '"[{\"he\": \"הסרט קיבל ביקורות רעות, בכל זאת הלכתי לראות אותו\", \"ru\": \"Фильм получил плохие отзывы, тем не менее я пошёл его смотреть\", \"translit\": \"ха-серет кибель бикорот раот, бехоль зот hалахти лиръот ото\"}, {\"he\": \"המשכורת נמוכה, עם זאת העבודה מעניינת\", \"ru\": \"Зарплата низкая, вместе с тем работа интересная\", \"translit\": \"ха-маскорет немуха, им зот ха-авода меаньенет\"}, {\"he\": \"הוא לא התכונן, ובכל אופן עבר את המבחן\", \"ru\": \"Он не готовился, и в любом случае сдал экзамен\", \"translit\": \"ху ло хитконен, у-вехоль офен авар эт ха-мивхан\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (162, 60, 'Основные временные союзы: כְּשֶׁ / כַּאֲשֶׁר (когда), לִפְנֵי שֶׁ (прежде чем), אַחֲרֵי שֶׁ (после того как), עַד שֶׁ (пока не), מֵאָז שֶׁ (с тех пор как). Согласование времён: после לפני ש и אחרי ש глагол обычно стоит в прошедшем времени в рассказе о прошлом.', '"[{\"he\": \"כשהגעתי הביתה, כבר היה חושך\", \"ru\": \"Когда я добрался домой, уже было темно\", \"translit\": \"кше-hигати ха-байта, квар hая хошех\"}, {\"he\": \"לפני שיצאתי מהבית, בדקתי את מזג האוויר\", \"ru\": \"Прежде чем я вышел из дома, я проверил погоду\", \"translit\": \"лифней ше-яцати ме-ха-байт, бадакти эт мезег ха-авир\"}, {\"he\": \"מאז שעברנו לתל אביב, החיים השתנו\", \"ru\": \"С тех пор как мы переехали в Тель-Авив, жизнь изменилась\", \"translit\": \"меаз ше-аварну ле-тель-авив, ха-хаим хиштану\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (163, 60, 'Союзы одновременности и последовательности: בִּזְמַן שֶׁ (в то время как), בְּעוֹד (в то время как / тогда как), טֶרֶם (прежде чем — литературный). בזמן ש описывает одновременные действия, בעוד может выражать также противопоставление, טרם используется в книжной речи вместо לפני ש.', '"[{\"he\": \"בזמן שאני מבשל, היא קוראת ספר\", \"ru\": \"Пока я готовлю, она читает книгу\", \"translit\": \"бизман ше-ани мевашель, хи корэт сефер\"}, {\"he\": \"בעוד הוא אוהב מוזיקה קלאסית, היא מעדיפה רוק\", \"ru\": \"Тогда как он любит классическую музыку, она предпочитает рок\", \"translit\": \"беод ху оhев музика класит, хи маадифа рок\"}, {\"he\": \"הוא הגיע טרם סיימנו את הישיבה\", \"ru\": \"Он прибыл прежде, чем мы закончили собрание\", \"translit\": \"ху hигиа терем сиямну эт ха-йешива\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (164, 61, 'Цель выражается конструкциями: כְּדֵי לְ + инфинитив (для того чтобы), בִּשְׁבִיל לְ + инфинитив (для того чтобы, разг.). Когда у действия и цели разные подлежащие, используется כְּדֵי שֶׁ + будущее время: כדי שתבין (чтобы ты понял).', '"[{\"he\": \"אני לומד עברית כדי למצוא עבודה טובה\", \"ru\": \"Я учу иврит, чтобы найти хорошую работу\", \"translit\": \"ани ломед иврит кдей лимцо авода това\"}, {\"he\": \"היא קמה מוקדם בשביל להספיק לרכבת\", \"ru\": \"Она встала рано, чтобы успеть на поезд\", \"translit\": \"хи кама мукдам бишвиль леhаспик ла-ракевет\"}, {\"he\": \"דיברתי לאט כדי שהם יבינו אותי\", \"ru\": \"Я говорил медленно, чтобы они меня поняли\", \"translit\": \"дибарти леат кдей ше-hем явину оти\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (165, 61, 'Формальные целевые конструкции: עַל מְנָת לְ (для того чтобы, офиц.), לְשֵׁם כָּךְ (для этой цели), לְמַעַן (ради, возвышенный стиль). על מנת ל используется в официальных текстах и деловой переписке, למען — в пафосной речи и лозунгах.', '"[{\"he\": \"על מנת להירשם, יש למלא טופס\", \"ru\": \"Для того чтобы зарегистрироваться, нужно заполнить форму\", \"translit\": \"аль менат леhирашем, йеш лемале тофес\"}, {\"he\": \"למדנו הרבה, ולשם כך הקדשנו כל ערב\", \"ru\": \"Мы много учились, и для этого посвящали каждый вечер\", \"translit\": \"ламадну hарбэ, у-лешем ках hикдашну коль эрев\"}, {\"he\": \"הם נלחמו למען השלום\", \"ru\": \"Они боролись ради мира\", \"translit\": \"hем нильхаму лемаан ха-шалом\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (166, 62, 'Многие глаголы в иврите требуют определённых предлогов. Основные сочетания: לְהִתְעַנְיֵין בְּ (интересоваться чем-то), לִדְאוֹג לְ (заботиться/волноваться о), לְהִתְרַגֵּל לְ (привыкнуть к), לִסְמוֹךְ עַל (полагаться на). Предлоги нужно заучивать вместе с глаголом.', '"[{\"he\": \"אני מתעניין באמנות מודרנית\", \"ru\": \"Я интересуюсь современным искусством\", \"translit\": \"ани митаньен бе-оманут модернит\"}, {\"he\": \"היא דואגת לילדים שלה כל הזמן\", \"ru\": \"Она заботится о своих детях всё время\", \"translit\": \"хи доэгет ла-йеладим шела коль ха-зман\"}, {\"he\": \"לקח לי זמן להתרגל לאקלים\", \"ru\": \"Мне потребовалось время, чтобы привыкнуть к климату\", \"translit\": \"лаках ли зман леhитрагель ла-аклим\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (167, 62, 'Некоторые глаголы меняют значение в зависимости от предлога: לַעֲבוֹד (работать) vs. לַעֲבוֹד עַל (работать над), לַחְשׁוֹב (думать) vs. לַחְשׁוֹב עַל (думать о чём-то) vs. לַחְשׁוֹב מִ (думать/быть мнения о ком-то). Выбор предлога существенно влияет на смысл.', '"[{\"he\": \"הוא עובד בבנק, אבל עכשיו עובד על פרויקט חדש\", \"ru\": \"Он работает в банке, но сейчас работает над новым проектом\", \"translit\": \"ху овед бе-банк, аваль ахшав овед аль проект хадаш\"}, {\"he\": \"אני חושב על החופשה שלנו\", \"ru\": \"Я думаю о нашем отпуске\", \"translit\": \"ани хошев аль ха-хуфша шелану\"}, {\"he\": \"מה את חושבת ממנו?\", \"ru\": \"Что ты о нём думаешь? (какого мнения)\", \"translit\": \"ма ат хошевет мимену?\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (168, 63, 'Дискурсивные маркеры: בְּעֶצֶם (на самом деле/собственно), דַּוְקָא (именно/как раз наоборот), כְּאִילוּ (как будто/типа), בִּכְלָל (вообще), מַמָּשׁ (реально/очень). Эти слова придают речи естественность и широко используются в разговорном иврите.', '"[{\"he\": \"בעצם, רציתי לשאול אותך משהו אחר\", \"ru\": \"Собственно, я хотел тебя спросить кое-что другое\", \"translit\": \"беэцем, рацити лишъоль отха машеhу ахер\"}, {\"he\": \"דווקא היום הוא החליט לבוא\", \"ru\": \"Именно сегодня он решил прийти\", \"translit\": \"давка ха-йом ху hехлит лаво\"}, {\"he\": \"האוכל שם ממש טעים, אני בכלל לא מבין למה אנשים מתלוננים\", \"ru\": \"Еда там реально вкусная, я вообще не понимаю, почему люди жалуются\", \"translit\": \"ха-охель шам мамаш таим, ани бихлаль ло мевин лама анашим митлонним\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (169, 63, 'Фокусные частицы: אֲפִילוּ (даже), לְפָחוֹת (по крайней мере), בְּעִיקָר (в основном/главным образом), בְּדִיּוּק (точно/именно), כִּמְעַט (почти). Эти частицы выделяют или ограничивают часть высказывания.', '"[{\"he\": \"אפילו הילדים הבינו את הבעיה\", \"ru\": \"Даже дети поняли проблему\", \"translit\": \"афилу ха-йеладим hевину эт ха-беая\"}, {\"he\": \"אני בעיקר אוהב לקרוא ספרי מדע בדיוני\", \"ru\": \"Я в основном люблю читать научную фантастику\", \"translit\": \"ани беикар оhев ликро сифрей мада бидйони\"}, {\"he\": \"כמעט שכחתי לספר לך, לפחות תזכיר לי מחר\", \"ru\": \"Я чуть не забыл тебе рассказать, по крайней мере напомни мне завтра\", \"translit\": \"кимъат шахахти лесапер леха, лефахот тазкир ли махар\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (170, 64, 'Пунктуация в иврите: точка, запятая, вопросительный и восклицательный знаки — как в европейских языках. Двоеточие ставится перед прямой речью: הוא אמר: «אני בא». Кавычки: «» (ёлочки) или "" (двойные). В иврите также используется גֵּרֶשׁ (׳) и גֵּרְשַׁיִם (״) для аббревиатур.', '"[{\"he\": \"המורה שאל: \\\"מי רוצה לענות?\\\"\", \"ru\": \"Учитель спросил: \\\"Кто хочет ответить?\\\"\", \"translit\": \"ха-морэ шааль: \\\"ми роцэ лаанот?\\\"\"}, {\"he\": \"צה\\\"ל — צבא ההגנה לישראל\", \"ru\": \"ЦАХАЛ — Армия обороны Израиля (гершаим в аббревиатуре)\", \"translit\": \"цаhаль — цва ха-hагана ле-исраэль\"}, {\"he\": \"הוא אמר: «אני לא מסכים!»\", \"ru\": \"Он сказал: «Я не согласен!»\", \"translit\": \"ху амар: «ани ло маским!»\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (171, 64, 'Связующие слова для структуры текста: רֵאשִׁית (во-первых), שֵׁנִית (во-вторых), לְבַסּוֹף (в конце концов/наконец), לְסִיכּוּם (в заключение/подводя итог), מִצַּד אֶחָד...מִצַּד שֵׁנִי (с одной стороны...с другой стороны). Используются в эссе, докладах и аргументированной речи.', '"[{\"he\": \"ראשית, צריך להבין את הבעיה, שנית, למצוא פתרון\", \"ru\": \"Во-первых, нужно понять проблему, во-вторых, найти решение\", \"translit\": \"решит, царих леhавин эт ха-беая, шенит, лимцо питарон\"}, {\"he\": \"מצד אחד זה יקר, אבל מצד שני האיכות מעולה\", \"ru\": \"С одной стороны это дорого, но с другой стороны качество отличное\", \"translit\": \"ми-цад эхад зэ якар, аваль ми-цад шени ха-эйхут меула\"}, {\"he\": \"לסיכום, הפרויקט הצליח הודות לעבודת צוות\", \"ru\": \"Подводя итог, проект удался благодаря командной работе\", \"translit\": \"лесикум, ха-проект hицлиах hодот ла-аводат цевет\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (172, 20, 'Конструкция הַלְוַאי שֶׁ (если бы / о если бы) выражает нереализованное желание. С будущим временем — реальное пожелание: הלוואי שיבוא (хоть бы он пришёл). С прошедшим временем — сожаление о несбывшемся: הלוואי שבאתי (если бы я пришёл). Частица לוּ (литературное «если бы») используется в условных предложениях нереального условия: לוּ ידעתי, הייתי בא (если бы я знал, я бы пришёл).', '"[{\"he\": \"הלוואי שהייתי לומד עברית כשהייתי צעיר יותר\", \"ru\": \"Если бы я учил иврит, когда был моложе\", \"translit\": \"hалевай ше-hаити ломед иврит кше-hаити цаир йотер\"}, {\"he\": \"לו יכולתי לחזור בזמן, הייתי בוחר אחרת\", \"ru\": \"Если бы я мог вернуться во времени, я бы выбрал иначе\", \"translit\": \"лу яхольти лахзор ба-зман, hаити бохер ахерет\"}, {\"he\": \"הלוואי שייגמר המשבר הכלכלי בקרוב\", \"ru\": \"Хоть бы экономический кризис скоро закончился\", \"translit\": \"hалевай ше-йигамер ха-машбер ха-калькали бе-каров\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (173, 20, 'Конструкция אִילוּ (если бы — контрфактическое условие) вводит нереальное условие в прошлом или настоящем. Структура: אילו + прошедшее время, הייתי + причастие (результат). Отличие от לו: אילו более нейтрально и распространено в современном иврите, לו — возвышенный стиль. Конструкция שֶׁמָּא (как бы не / а вдруг) выражает опасение.', '"[{\"he\": \"אילו למדת יותר, היית מצליח במבחן\", \"ru\": \"Если бы ты больше учился, ты бы сдал экзамен\", \"translit\": \"илу ламадта йотер, hаита мацлиах ба-мивхан\"}, {\"he\": \"אילו היינו יודעים מראש, היינו מתכוננים אחרת\", \"ru\": \"Если бы мы знали заранее, мы бы подготовились иначе\", \"translit\": \"илу hаину йодим мерош, hаину миткононим ахерет\"}, {\"he\": \"הוא חשש שמא יפסיד את המשרה בגלל האיחור\", \"ru\": \"Он опасался, как бы не потерять должность из-за опоздания\", \"translit\": \"ху хашаш шема яфсид эт ха-масра бигляль ха-ихур\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (174, 65, 'Инверсия порядка слов для эмфазы: вынесение дополнения или обстоятельства в начало предложения (топикализация). Нейтральный порядок: подлежащее + сказуемое + дополнение. Эмфатический: дополнение + подлежащее + сказуемое. Частица דַּוְקָא (именно / как раз наоборот) подчёркивает контраст или неожиданность, ставится перед выделяемым словом.', '"[{\"he\": \"את הספר הזה דווקא כן קראתי, אבל לא התרשמתי\", \"ru\": \"Именно эту книгу я как раз прочитал, но не впечатлился\", \"translit\": \"эт ха-сефер ха-зэ давка кен карати, аваль ло хитрашамти\"}, {\"he\": \"בישיבה הזאת דווקא הוא היה הכי רלוונטי\", \"ru\": \"Именно на этом совещании он был самым уместным\", \"translit\": \"ба-йешива ха-зот давка ху hая hахи релеванти\"}, {\"he\": \"את התפקיד הזה הציעו לי, לא לו\", \"ru\": \"Эту должность предложили мне, а не ему\", \"translit\": \"эт ха-тафкид ха-зэ hэциу ли, ло ло\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (175, 65, 'Усилительные частицы הֲרֵי (ведь / же), אָכֵן (действительно / в самом деле) и אָמְנָם (хотя / правда). הרי вводит известный факт как обоснование: הרי אמרתי לך (я ведь тебе говорил). אכן подтверждает сказанное: אכן, צדקת (действительно, ты был прав). אמנם вводит уступку: אמנם קשה, אבל אפשרי (хоть и трудно, но возможно).', '"[{\"he\": \"הרי ידוע שהמצב הכלכלי משפיע על החינוך\", \"ru\": \"Ведь известно, что экономическое положение влияет на образование\", \"translit\": \"hарей ядуа ше-ха-мацав ха-калькали машпиа аль ха-хинух\"}, {\"he\": \"אכן, המחקר הוכיח את ההשערה שלנו\", \"ru\": \"Действительно, исследование подтвердило нашу гипотезу\", \"translit\": \"ахен, ха-мехкар хохиах эт ха-hашъара шелану\"}, {\"he\": \"אמנם הפרויקט מורכב, אבל הצוות שלנו מנוסה מספיק\", \"ru\": \"Хоть проект и сложный, но наша команда достаточно опытная\", \"translit\": \"омнам ха-проект муркав, аваль ха-цевет шелану менусэ маспик\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (176, 66, 'Трёхбуквенный корень (שׁוֹרֶשׁ) — основа словообразования в иврите. Один корень порождает слова в разных биньянах с закономерными сдвигами значения. Например, корень כ.ת.ב: כָּתַב (пааль — писал), נִכְתַּב (нифъаль — был написан), הִכְתִּיב (хифъиль — диктовал), הִתְכַּתֵּב (хитпаэль — переписывался). Распознавание корня позволяет понимать незнакомые слова по аналогии.', '"[{\"he\": \"מהשורש ל.מ.ד נגזרים: לָמַד, לִימֵּד, תַּלְמִיד, לִימּוּד, מְלַמֵּד\", \"ru\": \"От корня л.м.д образуются: учился, обучал, ученик, учёба, учитель\", \"translit\": \"ме-ха-шореш л.м.д нигзарим: ламад, лимед, тальмид, лимуд, меламед\"}, {\"he\": \"השורש ש.מ.ר: שָׁמַר, נִשְׁמַר, הִשְׁתַּמֵּר, מִשְׁמָר, שְׁמִירָה\", \"ru\": \"Корень ш.м.р: охранял, сохранился, законсервировался, караул, охрана\", \"translit\": \"ха-шореш ш.м.р: шамар, нишмар, хиштамер, мишмар, шмира\"}, {\"he\": \"אם אתה מזהה את השורש ח.ש.ב, תבין גם: מַחְשָׁבָה, חִישׁוּב, מַחְשֵׁב, חֶשְׁבּוֹן\", \"ru\": \"Если ты узнаёшь корень х.ш.в, поймёшь и: мысль, вычисление, компьютер, счёт\", \"translit\": \"им ата мезаhэ эт ха-шореш х.ш.в, тавин гам: махшава, хишув, махшев, хешбон\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (189, 74, 'Дополнительные сложные союзы: כָּכָל שֶׁ (по мере того как / чем больше…тем), וּבִלְבַד שֶׁ (при условии что / лишь бы), בְּתְנַאי שֶׁ (при условии что). ככל ש используется в корреляционных конструкциях: ככל ש...כך... (чем больше...тем больше). ובלבד ש и בתנאי ש выражают ограничительное условие.', '"[{\"he\": \"ככל שהמחקר מתקדם, כך מתגלים ממצאים חדשים\", \"ru\": \"По мере продвижения исследования обнаруживаются новые данные\", \"translit\": \"кахоль ше-ха-мехкар миткадем, ках митгалим мимцаим хадашим\"}, {\"he\": \"ניתן להשתמש בחומר ובלבד שיינתן קרדיט למחבר\", \"ru\": \"Можно использовать материал при условии, что будет указан автор\", \"translit\": \"нитан леhиштамеш ба-хомер у-вильвад ше-йинатен кредит ла-мехабер\"}, {\"he\": \"אני מסכים, בתנאי שהתנאים יישארו כפי שנקבעו\", \"ru\": \"Я согласен при условии, что условия останутся такими, как были определены\", \"translit\": \"ани маским, би-тнай ше-ха-тнаим йишару кфи ше-никву\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (177, 66, 'Практическая стратегия: при встрече с незнакомым словом выделите три согласные буквы корня, отбросив приставки (מ, ה, ת, נ) и суффиксы. Затем вспомните известные слова с тем же корнем. Четырёхбуквенные корни (שורש רבע-עיצורי) тоже существуют, но редки: т.р.г.м (перевод), т.к.ш.р (связь). Слабые корни содержат «слабые» буквы (נ, י, ו), которые могут выпадать при словоизменении.', '"[{\"he\": \"המילה ''הִתְקַדְּמוּת'' — מ/ת/ה = приставки, שורש: ק.ד.מ (перёд, прогресс)\", \"ru\": \"Слово ''hиткадмут'' — м/т/h = приставки, корень: к.д.м (перёд, прогресс)\", \"translit\": \"ха-мила ''hиткадмут'' — м/т/h = приставки, шореш: к.д.м\"}, {\"he\": \"שורש נ.פ.ל — נָפַל, הִפִּיל, מַפָּלָה: ה-נ'' נופלת בהפעיל\", \"ru\": \"Корень н.п.л — упал, уронил, поражение: буква нун выпадает в hифъиль\", \"translit\": \"шореш н.п.л — нафаль, hипиль, мапала: ха-нун нофелет бе-hифъиль\"}, {\"he\": \"תרגום, תקשורת — שורשים בני ארבע אותיות: ת.ר.ג.מ, ת.ק.ש.ר\", \"ru\": \"Перевод, коммуникация — четырёхбуквенные корни: т.р.г.м, т.к.ш.р\", \"translit\": \"таргум, тикшорет — шорашим бней арба отийот: т.р.г.м, т.к.ш.р\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (178, 67, 'Мишкаль (משקל) — это шаблон словообразования, который определяет грамматическую категорию и оттенок значения слова. Основные именные мишкали: CaCaC (действие/процесс: דָּבָר — вещь), CiCuC (отглагольное сущ. от пиэль: דִּיבּוּר — речь), CCiCa (действие от пааль: כְּתִיבָה — писание), maCCeC (инструмент/устройство: מַחְשֵׁב — компьютер), taCCiC (продукт/результат: תַּקְצִיב — бюджет).', '"[{\"he\": \"משקל קִיטּוּל: דִּיבּוּר (речь), שִׁיפּוּר (улучшение), תִּיקּוּן (починка)\", \"ru\": \"Мишкаль киттуль: дибур (речь), шипур (улучшение), тикун (починка)\", \"translit\": \"мишкаль китуль: дибур, шипур, тикун\"}, {\"he\": \"משקל מַקְטֵל: מַזְלֵג (вилка), מַסְפֵּר (ножницы), מַחְשֵׁב (компьютер)\", \"ru\": \"Мишкаль мактель: мазлег (вилка), маспер (ножницы), махшев (компьютер)\", \"translit\": \"мишкаль мактель: мазлег, маспер, махшев\"}, {\"he\": \"משקל קַטְלָן: סַבְלָן (терпеливый), רַגְזָן (раздражительный), שַׁקְרָן (лжец)\", \"ru\": \"Мишкаль катлан: савлан (терпеливый), рагзан (раздражительный), шакран (лжец)\", \"translit\": \"мишкаль катлан: савлан, рагзан, шакран\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (179, 67, 'Мишкали прилагательных: CaCiC (свойство: גָּדוֹל — большой, но также חָרִיף — острый), CaCuC (пассивное свойство: כָּתוּב — написанный, שָׁבוּר — сломанный), CCoCeC (активное причастие пааль: כּוֹתֵב — пишущий). Абстрактные существительные: CCiCut (абстракция: חֲשִׁיבוּת — важность), CaCCa (профессия/хобби: רַפּוּאָה — медицина). Зная мишкаль, можно предсказать значение нового слова.', '"[{\"he\": \"משקל קָטוּל: כָּתוּב (написанный), שָׁמוּר (сохранённый), יָדוּעַ (известный)\", \"ru\": \"Мишкаль катуль: катув (написанный), шамур (сохранённый), ядуа (известный)\", \"translit\": \"мишкаль катуль: катув, шамур, ядуа\"}, {\"he\": \"משקל קְטִילוּת: חֲשִׁיבוּת (важность), רְצִינוּת (серьёзность), יְעִילוּת (эффективность)\", \"ru\": \"Мишкаль ктилут: хашивут (важность), рцинут (серьёзность), йеилут (эффективность)\", \"translit\": \"мишкаль ктилут: хашивут, рцинут, йеилут\"}, {\"he\": \"אם אתה רואה מילה במשקל מִקְטָל, זה כנראה מקום: מִכְלָל (колледж), מִפְעָל (завод)\", \"ru\": \"Если ты видишь слово в мишкале микталь, это вероятно место: михлаль (колледж), мифъаль (завод)\", \"translit\": \"им ата роэ мила бе-мишкаль микталь, зэ канирэ маком: михлаль, мифъаль\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (180, 69, 'Коллокации — устойчивые сочетания слов, которые носители используют автоматически. Глагольные коллокации: קִיבֵּל הַחְלָטָה (принял решение), נָשָׂא נְאוּם (произнёс речь), עָרַךְ טֶקֶס (провёл церемонию), פָּרַץ בִּבְכִי (разрыдался). Дословный перевод с русского часто не работает: «сильный дождь» — גֶּשֶׁם חָזָק (а не חזק в смысле «сильный физически»).', '"[{\"he\": \"ראש הממשלה נשא נאום בפני הכנסת בנושא הרפורמה\", \"ru\": \"Глава правительства произнёс речь перед Кнессетом на тему реформы\", \"translit\": \"рош ха-мемшала наса неум бифней ха-кнесет бе-носэ ха-реформа\"}, {\"he\": \"הוועדה קיבלה החלטה פה אחד לדחות את ההצעה\", \"ru\": \"Комитет единогласно принял решение отклонить предложение\", \"translit\": \"ха-ваада кибла хахлата пэ эхад лидхот эт ха-hацаа\"}, {\"he\": \"הילד פרץ בבכי כשגילה שהכלב ברח מהבית\", \"ru\": \"Ребёнок разрыдался, когда обнаружил, что собака убежала из дома\", \"translit\": \"ха-йелед парац бивхи кше-гила ше-ха-келев барах ме-ха-байт\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (181, 69, 'Именные коллокации (смихут и свободные сочетания): שְׁעַת שִׂיא (час пик), קַו תַּחְתּוֹן (нижняя черта / суть), מַצַּב רוּחַ (настроение), תְּשׂוּמַת לֵב (внимание). Предложные коллокации: בְּהֶחְלֵט (решительно / однозначно), בְּהַחְלָט לֹא (категорически нет), מֵרֹאשׁ (заранее), עַל הַפָּנִים (ужасно, разг.). Эти сочетания нельзя разложить на части — их запоминают как единое целое.', '"[{\"he\": \"בשעת שיא הפקקים בתל אביב נמשכים שעות\", \"ru\": \"В час пик пробки в Тель-Авиве длятся часами\", \"translit\": \"бе-шаат сиа ха-пкаким бе-тель-авив нимшахим шаот\"}, {\"he\": \"הקו התחתון הוא שאנחנו צריכים לשנות את הגישה שלנו\", \"ru\": \"Суть в том, что нам нужно изменить наш подход\", \"translit\": \"ха-кав ха-тахтон ху ше-анахну црихим лешанот эт ха-гиша шелану\"}, {\"he\": \"צריך להזמין כרטיסים מראש כי ההצגה תמיד מלאה\", \"ru\": \"Нужно заказывать билеты заранее, потому что спектакль всегда полный\", \"translit\": \"царих леhазмин картисим мерош ки ха-hацага тамид мелеа\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (182, 70, 'Пассивные биньяны (нифъаль, пуаль, хуфъаль) используются, когда действие важнее деятеля. Нифъаль (נִקְטַל): נִבְנָה (был построен), נִכְתַּב (был написан). Пуаль (קֻטַּל): בּוּצַּע (был выполнен), סוּפַּר (было рассказано). Хуфъаль (הוּקְטַל): הוּזְמַן (был приглашён), הוּחְלַט (было решено). Выбор биньяна зависит от активного аналога: если активная форма в пиэль — пассив будет в пуаль.', '"[{\"he\": \"בית הספר נבנה בשנות השישים והוא שופץ לאחרונה\", \"ru\": \"Школа была построена в шестидесятые годы и недавно отремонтирована\", \"translit\": \"бейт ха-сефер нивна бе-шнот ха-шишим ве-ху шупац лаахрона\"}, {\"he\": \"ההחלטה הוחלטה ברמה הממשלתית ובוצעה מיד\", \"ru\": \"Решение было принято на правительственном уровне и выполнено немедленно\", \"translit\": \"ха-hахлата hухлета ба-рама ха-мемшалтит ве-буцъа миад\"}, {\"he\": \"המכתב נכתב בעברית אך תורגם לאנגלית\", \"ru\": \"Письмо было написано на иврите, но переведено на английский\", \"translit\": \"ха-михтав нихтав бе-иврит ах тургам ле-англит\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (183, 70, 'Безличные конструкции используют слова אֶפְשָׁר (можно), צָרִיךְ (нужно/надо), אָסוּר (запрещено), כְּדַאי (стоит/целесообразно) + инфинитив. В отличие от пассива, здесь нет скрытого деятеля. Различие: הוּחְלַט לדחות (было решено отложить — кто-то решил) vs. צָרִיךְ לדחות (нужно отложить — общая необходимость). В официальных текстах часто: יֵשׁ לְ + инфинитив (следует).', '"[{\"he\": \"אי אפשר להתעלם מהבעיה הזאת, צריך לטפל בה מיד\", \"ru\": \"Невозможно игнорировать эту проблему, нужно заняться ей немедленно\", \"translit\": \"и эфшар леhитъалем ме-ха-беая ха-зот, царих летапель ба миад\"}, {\"he\": \"אסור לעשן בבניינים ציבוריים, כדאי לצאת החוצה\", \"ru\": \"Запрещено курить в общественных зданиях, стоит выйти наружу\", \"translit\": \"асур леашен бе-вньяним циборийим, кедай лацет ха-хуца\"}, {\"he\": \"יש להגיש את הטפסים עד סוף החודש\", \"ru\": \"Следует подать формы до конца месяца\", \"translit\": \"йеш леhагиш эт ха-тфасим ад соф ха-ходеш\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (184, 71, 'Безличные конструкции для эмоций: חֲבָל שֶׁ (жаль, что), מַזָּל שֶׁ (повезло, что), אִכְפַּת לִי (мне не всё равно), בָּא לִי (мне хочется, разг.). Структура: безличное выражение + ל + лицо (кому). Формальные: מְשַׂמֵּחַ אוֹתִי שֶׁ (меня радует, что), מְדַאֵג אוֹתִי שֶׁ (меня беспокоит, что). Разговорные: בָּא לִי, נִמְאַס לִי (мне надоело), חוֹלֵם עַל (мечтаю о).', '"[{\"he\": \"חבל שלא הגעת לאירוע, היה ממש מעניין\", \"ru\": \"Жаль, что ты не пришёл на мероприятие, было очень интересно\", \"translit\": \"хаваль ше-ло hигата ла-ируа, hая мамаш меаньен\"}, {\"he\": \"לא אכפת לי מה חושבים אחרים, אני הולך בדרך שלי\", \"ru\": \"Мне всё равно, что думают другие, я иду своим путём\", \"translit\": \"ло ихпат ли ма хошвим ахерим, ани hолех ба-дерех шели\"}, {\"he\": \"נמאס לי מהפקקים, בא לי לעבור לעבוד מהבית\", \"ru\": \"Мне надоели пробки, мне хочется перейти на работу из дома\", \"translit\": \"нимас ли ме-ха-пкаким, ба ли лаавор лаавод ме-ха-байт\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (185, 71, 'Выражение отношения в формальном и неформальном регистрах. Формально: אֲנִי סָבוּר שֶׁ (я полагаю, что), לְדַעְתִי (по моему мнению), יֵשׁ לְצַיֵּן שֶׁ (следует отметить, что). Разговорно: אֲנִי חוֹשֵׁב שֶׁ (я думаю, что), נִרְאֶה לִי שֶׁ (мне кажется, что), בְּטוּחַ שֶׁ (уверен, что). Эмоциональные восклицания: !אֵיזֶה כֵּיף (какой кайф!), !אֵיזֶה בָּאסָה (какой облом!), !לֹא יֵיאָמֵן (невероятно!).', '"[{\"he\": \"לדעתי, יש לנקוט צעדים מיידיים כדי לפתור את המשבר\", \"ru\": \"По моему мнению, следует предпринять немедленные шаги для решения кризиса\", \"translit\": \"ледаати, йеш линкот цъадим миядийим кдей лифтор эт ха-машбер\"}, {\"he\": \"נראה לי שהוא לא ממש מבין את חומרת המצב\", \"ru\": \"Мне кажется, он не совсем понимает серьёзность ситуации\", \"translit\": \"нирэ ли ше-ху ло мамаш мевин эт хумрат ха-мацав\"}, {\"he\": \"איזה כיף שסוף סוף הגעת! לא ייאמן כמה השתנית!\", \"ru\": \"Как здорово, что ты наконец приехал! Невероятно, как ты изменился!\", \"translit\": \"эйзэ кейф ше-соф соф hигата! ло йеамен кама хиштанита!\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (186, 73, 'Номинализация в иврите — это образование абстрактных существительных от глагольных корней. Основные модели: קְטִילָה (ктила) для действия (כְּתִיבָה — написание, קְרִיאָה — чтение), קִטּוּל (киттуль) для процесса/результата (עִיבּוּד — обработка, שִׁיפּוּר — улучшение), הַקְטָלָה (hактала) для каузатива (הַשְׁפָּעָה — влияние, הַחְלָטָה — решение). Номинализации широко используются в академическом и юридическом иврите.', '"[{\"he\": \"הפנמת הערכים מתבצעת באמצעות חינוך מתמשך\", \"ru\": \"Интернализация ценностей осуществляется посредством непрерывного воспитания\", \"translit\": \"ха-hафнамат ха-арахим митбацеет бе-эмцаут хинух митмашех\"}, {\"he\": \"התפתחותה של השפה העברית משקפת תהליכי מודרניזציה\", \"ru\": \"Развитие языка иврит отражает процессы модернизации\", \"translit\": \"хитпатхута шель ха-сафа ха-иврит мешакефет таhалихей модернизация\"}, {\"he\": \"הבנת הטקסט מחייבת ידע רחב בתחום הבלשנות\", \"ru\": \"Понимание текста требует широких познаний в области лингвистики\", \"translit\": \"hаванат ха-текст мехайевет йеда рахав ба-тхум ха-баланут\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (187, 73, 'Абстрактные существительные с суффиксами: -וּת (ут) образует абстракции от прилагательных (חָשׁוּב → חֲשִׁיבוּת — важность, אֶפְשָׁרִי → אֶפְשָׁרוּת — возможность), -יוּת (ют) для качественных понятий (אַחְרָיוּת — ответственность, רְצִינוּת — серьёзность). В академическом иврите эти формы заменяют описательные конструкции, делая текст более компактным.', '"[{\"he\": \"מורכבותו של הנושא מחייבת גישה רב-תחומית\", \"ru\": \"Сложность темы требует междисциплинарного подхода\", \"translit\": \"муркавуто шель ха-носе мехайевет гиша рав-тхумит\"}, {\"he\": \"ייחודיותה של התרבות העברית באה לידי ביטוי בספרות\", \"ru\": \"Уникальность еврейской культуры проявляется в литературе\", \"translit\": \"йихудиюта шель ха-тарбут ха-иврит баа лидей битуй ба-сифрут\"}, {\"he\": \"יעילותה של השיטה הוכחה במחקרים רבים\", \"ru\": \"Эффективность метода была доказана во многих исследованиях\", \"translit\": \"йеилута шель ха-шита hухха бе-мехкарим рабим\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (188, 74, 'Сложные подчинительные союзы высокого регистра: הוֹאִיל וְ (поскольку — юридический/канцелярский), בַּהֲנָחָה שֶׁ (при условии что / в предположении что), בְּהִתְחַשֵּׁב בְּ (с учётом / принимая во внимание). Эти союзы характерны для официальных документов, академических текстов и прессы. После הואיל ו используется причинное обоснование, после בהנחה ש — гипотетическое допущение.', '"[{\"he\": \"הואיל והנאשם לא התייצב לדיון, בית המשפט קבע דיון חוזר\", \"ru\": \"Поскольку обвиняемый не явился на заседание, суд назначил повторное слушание\", \"translit\": \"hоиль ве-ха-нээшам ло хитьяцев ла-диюн, бейт ха-мишпат кава диюн хозер\"}, {\"he\": \"בהנחה שהנתונים מדויקים, ניתן להסיק מסקנות ברורות\", \"ru\": \"При условии что данные точны, можно сделать чёткие выводы\", \"translit\": \"ба-hанаха ше-ха-нтуним медуяким, нитан леhасик маскано бруро\"}, {\"he\": \"בהתחשב בנסיבות, ההחלטה הייתה סבירה\", \"ru\": \"С учётом обстоятельств, решение было разумным\", \"translit\": \"бе-хитхашев ба-несибот, ха-hахлата hайта свира\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (190, 75, 'Логические коннекторы вывода и следствия: מִכָּאן שֶׁ (отсюда следует что), נוֹבֵעַ מִכָּךְ שֶׁ (из этого вытекает что), לְפִיכָךְ (следовательно / поэтому — формальный). Эти выражения используются в академическом дискурсе для построения аргументации. לפיכך — наиболее частый в юридических текстах, מכאן ש — в научных рассуждениях.', '"[{\"he\": \"מכאן שהתיאוריה אינה מסבירה את כלל התופעות\", \"ru\": \"Отсюда следует, что теория не объясняет всех явлений\", \"translit\": \"микан ше-ха-теория эйна масбира эт клаль ха-тофаот\"}, {\"he\": \"נובע מכך שיש צורך בגישה חדשה לבעיה\", \"ru\": \"Из этого вытекает, что необходим новый подход к проблеме\", \"translit\": \"новеа миках ше-йеш цорех бе-гиша хадаша ла-беая\"}, {\"he\": \"הנתונים סותרים את ההשערה, לפיכך יש לבחון אותה מחדש\", \"ru\": \"Данные противоречат гипотезе, следовательно, необходимо пересмотреть её\", \"translit\": \"ха-нтуним сотрим эт ха-hашеара, лефихах йеш ливхон ота ме-хадаш\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (191, 75, 'Выражения уверенности и модальности в аргументации: אֵין סָפֵק שֶׁ (нет сомнения что), בְּרוּר שֶׁ (очевидно что), מִסְתַּבֵּר שֶׁ (оказывается что / как выясняется), יִתָּכֵן שֶׁ (возможно что). Градация от полной уверенности (אין ספק ש) через очевидность (ברור ש) к допущению (יתכן ש) позволяет варьировать степень категоричности высказывания.', '"[{\"he\": \"אין ספק שהשפעת הטכנולוגיה על החברה היא עמוקה\", \"ru\": \"Нет сомнения, что влияние технологий на общество глубоко\", \"translit\": \"эйн сафек ше-hашпаат ха-технология аль ха-хевра хи амука\"}, {\"he\": \"מסתבר שהממצאים הראשוניים היו שגויים\", \"ru\": \"Как выясняется, первоначальные данные были ошибочными\", \"translit\": \"мистабер ше-ха-мимцаим ха-ришоним hаю шгуим\"}, {\"he\": \"יתכן שהפרשנות הזו אינה היחידה האפשרית\", \"ru\": \"Возможно, что эта интерпретация не единственно возможная\", \"translit\": \"йитахен ше-ха-паршанут ха-зо эйна ха-йехида ха-эфшарит\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (192, 76, 'Метафора и метонимия в иврите: метафора (מֶטָפוֹרָה) — перенос значения по сходству (יְדֵי הַזְּמַן — руки времени), метонимия (מֶטוֹנִימְיָה) — замена по смежности (הַכְּנֶסֶת הֶחְלִיטָה — Кнессет решил, т.е. депутаты). Литературный иврит активно использует библейские аллюзии как стилистический приём, что придаёт тексту глубину и многозначность.', '"[{\"he\": \"ידי הזמן טשטשו את זכרונות העבר\", \"ru\": \"Руки времени стёрли воспоминания прошлого\", \"translit\": \"йедей ха-зман тиштешу эт зихронот ха-авар\"}, {\"he\": \"הלבנון שותק — אין תגובה רשמית מצד ממשלת ביירות\", \"ru\": \"Ливан молчит — нет официальной реакции со стороны правительства Бейрута\", \"translit\": \"ха-леванон шотек — эйн тгува ришмит ми-цад мемшелет бейрут\"}, {\"he\": \"דבריו היו כחרב פיפיות — מחמיאים ופוגעים בעת ובעונה אחת\", \"ru\": \"Его слова были обоюдоострым мечом — льстящие и ранящие одновременно\", \"translit\": \"дварав хаю ке-херев пифийот — махмиим ве-фогим бе-эт у-ве-она ахат\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (193, 76, 'Ирония (אִירוֹנְיָה) и литота (הַמְעָטָה) в иврите: ирония выражается через контекст и интонацию, часто маркируется кавычками в письменном тексте (הוא «מומחה» גדול). Литота — намеренное преуменьшение: לֹא מְעַט (немало = много), לֹא רַע (неплохо = хорошо), לֹא בְּדִיּוּק (не совсем = совсем нет). Эти приёмы характерны для публицистического и литературного стиля.', '"[{\"he\": \"הוא «מומחה» גדול — שלוש שנים לומד ועדיין לא יודע את היסודות\", \"ru\": \"Он большой «эксперт» — три года учится и всё ещё не знает основ\", \"translit\": \"ху «мумхе» гадоль — шалош шаним ломед ве-адаин ло йодеа эт ха-йесодот\"}, {\"he\": \"ביצועיו לא היו רעים — למעשה, הוא שבר שיא עולמי\", \"ru\": \"Его результаты были неплохими — на самом деле он побил мировой рекорд\", \"translit\": \"бицуав ло хаю раим — лемаасе, ху шавар сиа олами\"}, {\"he\": \"הפרויקט עלה לא מעט כסף, אך התוצאות הצדיקו את ההשקעה\", \"ru\": \"Проект стоил немало денег, но результаты оправдали вложения\", \"translit\": \"ха-проект ала ло меат кесеф, ах ха-тоцаот хицдику эт ха-hашкаа\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (194, 77, 'Интеграция заимствований в морфологическую систему иврита: иностранные слова адаптируются через глагольные биньяны. Пиэль: טֶלְפֵּן (позвонить, от telephone), פִילְטֵּר (фильтровать). Пуаль (пассив): טוּלְפַּן, פּוּלְטַר. Хитпаэль: הִתְעַדְכֵּן (обновиться, от עדכון). Заимствованные глаголы получают полную парадигму спряжения по биньяну.', '"[{\"he\": \"הוא טלפן למשרד כדי לתאם פגישה, אבל קו הטלפון היה תפוס\", \"ru\": \"Он позвонил в офис, чтобы согласовать встречу, но линия была занята\", \"translit\": \"ху тильпен ла-мисрад кдей летаем пгиша, аваль кав ха-телефон хая тафус\"}, {\"he\": \"המאמר מפרגן לגישה החדשה בחקר הבלשנות\", \"ru\": \"Статья поддерживает новый подход в исследовании лингвистики\", \"translit\": \"ха-маамар мефарген ла-гиша ха-хадаша бе-хекер ха-баланут\"}, {\"he\": \"התוכנה עודכנה באופן אוטומטי, והמערכת אותחלה מחדש\", \"ru\": \"Программа обновилась автоматически, и система перезагрузилась\", \"translit\": \"ха-тохна удкена бе-офен отомати, ве-ха-маарехет уткхела ме-хадаш\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (195, 77, 'Паттерны адаптации существительных и прилагательных: суффикс -צְיָה (-ция) для латинских заимствований (דֶּמוֹקְרַטְיָה, גְּלוֹבָּלִיזַצְיָה), суффикс -יסְט (-ист) для деятелей (אָנַלִיסְט, ז''וּרְנָלִיסְט). Множественное число заимствований образуется по правилам иврита: טֶלֶפוֹן → טֶלֶפוֹנִים, אוּנִיבֶרְסִיטָה → אוּנִיבֶרְסִיטָאוֹת. Академия языка иврит регулярно предлагает ивритские замены для иностранных слов.', '"[{\"he\": \"הגלובליזציה השפיעה על כלכלות מתפתחות באופן דרמטי\", \"ru\": \"Глобализация драматически повлияла на развивающиеся экономики\", \"translit\": \"ха-глобализация хишпиа аль калькалот митпатхот бе-офен драмати\"}, {\"he\": \"האקדמיה ללשון העברית הציעה את המונח «מישוון» במקום «דיגיטציה»\", \"ru\": \"Академия языка иврит предложила термин «мишвун» вместо «дигитизация»\", \"translit\": \"ха-академия ла-лашон ха-иврит хециа эт ха-мунах «мишвун» бимком «дигитация»\"}, {\"he\": \"הפרופסור הרצה על האינטראקציה בין טכנולוגיה לחברה\", \"ru\": \"Профессор прочёл лекцию о взаимодействии технологии и общества\", \"translit\": \"ха-професор хирца аль ха-интеракция бейн технология ле-хевра\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (196, 78, 'Экстрапозиция (הֲעָתָקָה) — одна из ключевых конструкций иврита. Подлежащее выносится в начало предложения и дублируется местоимением: הַסֵּפֶר הַזֶּה, הוּא מְעַנְיֵין מְאוֹד (Эта книга — она очень интересна). Топикализация (נוֹשֵׂא פְּסִיכוֹלוֹגִי) выделяет тему: אֶת הַסֵּפֶר הַזֶּה כְּבָר קָרָאתִי (Эту книгу я уже прочитал). Обе конструкции характерны для живой речи и публицистики.', '"[{\"he\": \"המחקר הזה, הוא מציג תמונה מורכבת של המציאות הלשונית\", \"ru\": \"Это исследование — оно представляет сложную картину языковой реальности\", \"translit\": \"ха-мехкар ха-зе, ху мациг тмуна муркевет шель ха-мециут ха-лешонит\"}, {\"he\": \"את ההשפעות ארוכות הטווח של התהליך עדיין אי אפשר להעריך\", \"ru\": \"Долгосрочные последствия этого процесса пока невозможно оценить\", \"translit\": \"эт ха-hашпаот арукот ха-тавах шель ха-таhалих адаин и эфшар леhаарих\"}, {\"he\": \"הסטודנטים שנרשמו מאוחר, להם לא הובטח מקום בקורס\", \"ru\": \"Студенты, которые записались поздно, — им не было гарантировано место на курсе\", \"translit\": \"ха-студентим ше-нирешму меухар, лаhем ло hувтах маком ба-курс\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (197, 78, 'Вложенные придаточные (מִשְׁפָּטִים מְקוּנָנִים) и расщеплённые предложения (מִשְׁפְּטֵי שֶׁסַע). Вложенность: הָאִישׁ שֶׁהָאִשָּׁה שֶׁפָּגַשְׁתִּי סִיפְּרָה עָלָיו (человек, о котором рассказала женщина, которую я встретил). Расщеплённые: מַה שֶׁ + глагол זֶה... (то, что... это...) для фокусирования информации: מה שחשוב זה לא התוצאה אלא התהליך.', '"[{\"he\": \"מה שמטריד אותי זה שהנתונים שהוצגו סותרים את המחקרים הקודמים\", \"ru\": \"Что меня беспокоит — это то, что представленные данные противоречат предыдущим исследованиям\", \"translit\": \"ма ше-матрид оти зе ше-ха-нтуним ше-hуцгу сотрим эт ха-мехкарим ха-кодмим\"}, {\"he\": \"ההחלטה שהתקבלה בוועדה שהוקמה לבחינת הנושא עוררה ביקורת\", \"ru\": \"Решение, принятое комиссией, созданной для рассмотрения вопроса, вызвало критику\", \"translit\": \"ха-hахлата ше-хиткабла ба-ваада ше-hукма ли-вхинат ха-носе орера бикорет\"}, {\"he\": \"מי שסבור שהבעיה פשוטה, הוא לא מכיר את כל היבטיה\", \"ru\": \"Кто считает, что проблема проста, тот не знает всех её аспектов\", \"translit\": \"ми ше-савур ше-ха-беая пшута, ху ло макир эт коль хибатеха\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (198, 79, 'Стратегии вежливости в иврите: косвенные просьбы через условное наклонение (הָיִיתָ יָכוֹל — ты бы мог), модальные формы (אֶפְשָׁר לְ — можно ли), хеджирование (כְּאִילוּ — как бы, נִדְמֶה לִי שֶׁ — мне кажется что). В отличие от русского, иврит часто использует будущее время для смягчённых просьб: תוּכַל לַעֲזוֹר לִי? (Сможешь мне помочь?) вместо императива.', '"[{\"he\": \"סליחה, הייתי רוצה לשאול אם אפשר לקבל הארכה להגשת העבודה\", \"ru\": \"Извините, я бы хотел спросить, можно ли получить продление срока сдачи работы\", \"translit\": \"слиха, hаити роцэ лишъоль им эфшар лекабель hаарха ле-hагашат ха-авода\"}, {\"he\": \"נדמה לי שיש כאן אי-הבנה, אולי כדאי לבדוק את הנתונים שוב\", \"ru\": \"Мне кажется, тут есть недоразумение, возможно стоит проверить данные снова\", \"translit\": \"нидме ли ше-йеш кан и-hавана, улай кедай ливдок эт ха-нтуним шув\"}, {\"he\": \"אם זה לא מפריע לך, תוכל להעביר לי את החומר עד מחר?\", \"ru\": \"Если тебя не затруднит, ты мог бы передать мне материал до завтра?\", \"translit\": \"им зе ло мафриа леха, тухаль леhаавир ли эт ха-хомер ад махар?\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (199, 79, 'Косвенные речевые акты и прагматические маркеры: אַגַּב (кстати — для смены темы или добавления), בְּמִלִּים אֲחֵרוֹת (иными словами), אִם כָּבָר (уж если), אֵיךְ שֶׁלֹּא יִהְיֶה (как бы то ни было). Отказ в иврите часто смягчается: לֹא בָּטוּחַ שֶׁ (не уверен что) вместо прямого «нет», אֲנִי אֶבְדּוֹק (я проверю) как формула вежливого уклонения.', '"[{\"he\": \"אגב, רציתי להעיר שהנתונים שהצגת מעוררים כמה שאלות\", \"ru\": \"Кстати, я хотел заметить, что представленные тобой данные вызывают несколько вопросов\", \"translit\": \"агав, рацити леhаир ше-ха-нтуним ше-hицагта меорерим кама шеэлот\"}, {\"he\": \"אני לא בטוח שאוכל להגיע, אבל אני אבדוק ואחזור אליך\", \"ru\": \"Я не уверен, что смогу прийти, но я проверю и вернусь к тебе\", \"translit\": \"ани ло батуах ше-ухаль леhагиа, аваль ани эвдок ве-ахзор элеха\"}, {\"he\": \"איך שלא יהיה, עלינו למצוא פתרון שיהיה מקובל על כל הצדדים\", \"ru\": \"Как бы то ни было, мы должны найти решение, приемлемое для всех сторон\", \"translit\": \"эйх ше-ло йиhйе, алейну лимцо питарон ше-йиhйе мекубаль аль коль ха-цдадим\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (200, 80, 'Анафора и катафора — средства связности текста. Анафора (אָנָפוֹרָה) — ссылка назад: הַסֵּפֶר...הוּא (книга...она), הַנִּסּוּי...תּוֹצְאוֹתָיו (эксперимент...его результаты). Катафора (קָטָפוֹרָה) — ссылка вперёд: זֶה מָה שֶׁקָרָה... (вот что случилось...). Смычковые местоимения (הוא, היא, הם, זה, אלה) обеспечивают когезию абзаца и предотвращают повторы.', '"[{\"he\": \"המחקר בדק שלוש השערות; ממצאיו הראו שרק אחת מהן אוששה\", \"ru\": \"Исследование проверило три гипотезы; его результаты показали, что подтвердилась лишь одна из них\", \"translit\": \"ха-мехкар бадак шалош hашеарот; мимцаав hеръу ше-рак ахат ме-hен ушша\"}, {\"he\": \"זה מה שגילינו: הקשר בין המשתנים חזק יותר ממה שסברנו\", \"ru\": \"Вот что мы обнаружили: связь между переменными сильнее, чем мы предполагали\", \"translit\": \"зе ма ше-гилину: ха-кешер бейн ха-муштаним хазак йотер мима ше-саварну\"}, {\"he\": \"הוצגו שתי גישות; זו הראשונה מתמקדת בניתוח כמותי, ואילו זו השנייה — באיכותי\", \"ru\": \"Были представлены два подхода; первый сосредоточен на количественном анализе, тогда как второй — на качественном\", \"translit\": \"hуцгу штей гишот; зо ха-ришона митмакедет бе-нитуах камути, ве-илу зо ха-шния — бе-эйхути\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (201, 80, 'Дискурсивные коннекторы для когезии: יֶתֶר עַל כֵּן (более того), מֵאִידָךְ גִּיסָא (с другой стороны — арамеизм), נוֹסַף עַל כָּךְ (в дополнение к этому), לְעוּמַּת זֹאת (в противовес этому), דְּהַיְינוּ (то есть — арамеизм). Эти маркеры организуют логическую структуру текста: добавление (יתר על כן), противопоставление (מאידך גיסא), уточнение (דהיינו).', '"[{\"he\": \"המחקר מאשש את ההשערה; יתר על כן, הוא מציע מודל תיאורטי חדש\", \"ru\": \"Исследование подтверждает гипотезу; более того, оно предлагает новую теоретическую модель\", \"translit\": \"ха-мехкар меашеш эт ха-hашеара; йетер аль кен, ху мациа модель теорети хадаш\"}, {\"he\": \"מצד אחד, הרפורמה הגדילה את הנגישות; מאידך גיסא, היא פגעה באיכות\", \"ru\": \"С одной стороны, реформа повысила доступность; с другой стороны, она ухудшила качество\", \"translit\": \"ми-цад эхад, ха-реформа хигдила эт ха-нгишут; меидах гиса, хи пагъа бе-эйхут\"}, {\"he\": \"הניסוי כלל שלושה שלבים, דהיינו: איסוף נתונים, ניתוח וסיכום\", \"ru\": \"Эксперимент включал три этапа, а именно: сбор данных, анализ и подведение итогов\", \"translit\": \"ха-нисуй калаль шлоша шлавим, деhайну: исуф нтуним, нитуах ве-сикум\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (202, 81, 'Библейский иврит использует систему последовательных форм глагола, основанных на конструкции וַיִּקְטוֹל (вав-перевёртыш + имперфект) для повествования о прошлом. Эта форма, называемая «вав-последовательный» (וא"ו ההיפוך), превращает будущее время в прошедшее. Она является основной нарративной формой Библии и отсутствует в современном иврите.', '"[{\"he\": \"וַיֹּאמֶר אֱלֹהִים יְהִי אוֹר וַיְהִי אוֹר\", \"ru\": \"И сказал Бог: да будет свет. И стал свет.\", \"translit\": \"вайомер элоhим йеhи ор вайеhи ор\"}, {\"he\": \"וַיֵּלֶךְ אַבְרָם כַּאֲשֶׁר דִּבֶּר אֵלָיו ה׳\", \"ru\": \"И пошёл Аврам, как сказал ему Господь.\", \"translit\": \"вайелех аврам каашер дибер элав адонай\"}, {\"he\": \"וַיִּקַּח ה׳ אֱלֹהִים אֶת הָאָדָם וַיַּנִּחֵהוּ בְגַן עֵדֶן\", \"ru\": \"И взял Господь Бог человека и поместил его в саду Эдемском.\", \"translit\": \"вайиках адонай элоhим эт hа-адам вайанихеhу бе-ган эден\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (203, 81, 'Библейский синтаксис отличается от современного: инверсия подлежащего и сказуемого (VSO порядок вместо SVO), использование инфинитива абсолютного (מָקוֹר מֻחְלָט) для усиления глагола, а также конструкция waw-копулятивный + перфект (וְקָטַל) для обозначения будущих действий в пророческих текстах. Многие из этих форм сохранились в современной литературе как стилистические приёмы.', '"[{\"he\": \"מוֹת יָמוּת — הָאָדָם כִּי יָמוּת בְּאֹהֶל\", \"ru\": \"Смертью умрёт — человек, если умрёт в шатре (инфинитив абсолютный для усиления).\", \"translit\": \"мот ямут — hа-адам ки ямут бе-оhель\"}, {\"he\": \"וְאָהַבְתָּ אֵת ה׳ אֱלֹהֶיךָ בְּכָל לְבָבְךָ\", \"ru\": \"И возлюби Господа Бога твоего всем сердцем твоим (вав + перфект = императив).\", \"translit\": \"ве-аhавта эт адонай элоhеха бехоль левавха\"}, {\"he\": \"הָלוֹךְ וְגָדֵל — כְּמוֹ שֶׁאוֹמְרִים בַּתָּנָ\\\"ךְ\", \"ru\": \"Идя и увеличиваясь (всё более возрастая) — как говорят в Танахе.\", \"translit\": \"hалох ве-гадель — кмо ше-омрим ба-танах\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (204, 82, 'Мишнаитский иврит (иврит мудрецов, עברית חז"ל) — язык Мишны и Талмуда (I–V вв. н.э.), переходная форма между библейским и средневековым ивритом. Главные отличия от библейского: исчезновение системы вав-перевёртыша, появление аналитических временных конструкций с הָיָה + причастие (הָיָה עוֹשֶׂה), широкое заимствование из арамейского и греческого.', '"[{\"he\": \"הוּא הָיָה אוֹמֵר: אִם אֵין אֲנִי לִי, מִי לִי\", \"ru\": \"Он говаривал: если не я для себя, то кто для меня (Мишна, Авот 1:14).\", \"translit\": \"ху hая омер: им эйн ани ли, ми ли\"}, {\"he\": \"אַל תִּסְתַּכֵּל בַּקַּנְקַן אֶלָּא בְּמַה שֶׁיֵּשׁ בּוֹ\", \"ru\": \"Не смотри на кувшин, а на то, что в нём (Мишна, Авот 4:20).\", \"translit\": \"аль тистакель ба-канкан эла бе-ма ше-йеш бо\"}, {\"he\": \"תַּנָּא דְּבֵי רַבִּי יִשְׁמָעֵאל — термин из арамейско-ивритского Талмуда\", \"ru\": \"Таннай школы рабби Ишмаэля — пример смешения иврита и арамейского.\", \"translit\": \"тана де-вей раби ишмаэль\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (205, 82, 'Мишнаитский иврит значительно повлиял на современный иврит: из него заимствованы многие бытовые слова (שׁוּלְחָן — стол, כִּסֵּא — стул, חֲנוּת — магазин), грамматические конструкции (שֶׁל для выражения принадлежности вместо библейского סמיכות), а также порядок слов SVO, ставший нормой для современного языка. Бен-Йехуда сознательно опирался на мишнаитские формы при возрождении иврита.', '"[{\"he\": \"הַסֵּפֶר שֶׁל הַתַּלְמִיד — вместо סֵפֶר הַתַּלְמִיד\", \"ru\": \"Книга ученика — аналитическая форма (из Мишны) вместо библейского смихута.\", \"translit\": \"ха-сефер шель ха-тальмид — вместо сефер ха-тальмид\"}, {\"he\": \"חז\\\"ל אמרו: דֶּרֶךְ אֶרֶץ קָדְמָה לַתּוֹרָה\", \"ru\": \"Мудрецы сказали: нормы поведения предшествуют Торе.\", \"translit\": \"хазаль амру: дерех эрец кадма ла-тора\"}, {\"he\": \"בְּמִשְׁנָה כְּתוּב: הֱוֵי דָן אֶת כָּל הָאָדָם לְכַף זְכוּת\", \"ru\": \"В Мишне написано: суди каждого человека в его пользу.\", \"translit\": \"бе-мишна катув: hеве дан эт коль hа-адам лехаф зхут\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (206, 83, 'Академия языка иврит (הָאָקָדֶמְיָה לַלָּשׁוֹן הָעִבְרִית) — официальный орган, создающий новые слова для современных понятий. Основные стратегии: использование семитских корней в существующих моделях словообразования (מִשְׁקָלִים), возрождение библейских слов с новыми значениями и калькирование. Например: מַחְשֵׁב (компьютер, от корня ח-ש-ב «думать/считать»), סַמָּרְטְפוֹן (смартфон, от חָכָם — умный — не прижилось).', '"[{\"he\": \"הָאָקָדֶמְיָה הִמְלִיצָה עַל הַמִּלָּה \\\"מִרְשֶׁתֶת\\\" בִּמְקוֹם \\\"אִינְטֶרְנֶט\\\"\", \"ru\": \"Академия рекомендовала слово «миршетет» вместо «интернет» (от רֶשֶׁת — сеть).\", \"translit\": \"hа-академия hимлица аль hа-мила \\\"миршетет\\\" бимком \\\"интернет\\\"\"}, {\"he\": \"\\\"חַשְׁמַל\\\" — מִלָּה שֶׁיָּצַר בֶּן-יְהוּדָה מִתּוֹךְ סֵפֶר יְחֶזְקֵאל\", \"ru\": \"«Электричество» (хашмаль) — слово, которое Бен-Йехуда создал из книги Иезекииля.\", \"translit\": \"\\\"хашмаль\\\" — мила ше-яцар бен-йеhуда ми-тох сефер йехезкель\"}, {\"he\": \"בַּלְּשָׁנוּת הִיא תְּחוּם שֶׁחוֹקֵר אֶת הַשָּׂפָה בְּצוּרָה מַדָּעִית\", \"ru\": \"Лингвистика — это область, которая изучает язык научным образом.\", \"translit\": \"бальшанут hи тхум ше-хокер эт hа-сафа бе-цура мадаит\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (207, 83, 'Народное словотворчество идёт параллельно с академическим: спонтанные неологизмы часто обгоняют официальные. Продуктивные модели: глагольная деривация от заимствований (לְגוּגְלֵל — гуглить, לְפַרְגֵּן — радоваться чужому успеху), сложение основ (רֵאָלִי-טִי — реалити), аффиксация (אַפְּלִיקַצְיָה → אַפְּלִיקֵייְשֶׁן → אָפָּה). Многие заимствования со временем получают ивритский эквивалент, но далеко не все приживаются.', '"[{\"he\": \"הוּא גִּגְלֵל אֶת הַתַּשׁוּבָה בִּמְקוֹם לִפְתּוֹחַ סֵפֶר\", \"ru\": \"Он загуглил ответ вместо того чтобы открыть книгу.\", \"translit\": \"ху гиглель эт hа-тшува бимком лифтоах сефер\"}, {\"he\": \"תְּפָרְגֵּן לָהּ קְצָת, הִיא עָבְדָה קָשֶׁה עַל זֶה\", \"ru\": \"Порадуйся за неё немного, она тяжело над этим работала.\", \"translit\": \"тефарген ла кцат, хи авда каше аль зэ\"}, {\"he\": \"הָאָקָדֶמְיָה הִצִּיעָה \\\"יִשּׁוּמוֹן\\\" בִּמְקוֹם \\\"אַפְּלִיקַצְיָה\\\", אֲבָל אַף אֶחָד לֹא מִשְׁתַּמֵּשׁ בָּזֶה\", \"ru\": \"Академия предложила «йишумон» вместо «приложение», но никто этим не пользуется.\", \"translit\": \"hа-академия hицъиа \\\"йишумон\\\" бимком \\\"апликация\\\", аваль аф эхад ло миштамеш бе-зэ\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (208, 84, 'В современном иврите сохраняются следы различных произносительных традиций: ашкеназская (европейская) — ударение часто на предпоследнем слоге, различение ת рефуя (с) и ת дагеш (т), ш-произношение שׂ; мизрахийская (восточная) — различение эмфатических согласных ט/ת, ח-гортанное, ע-звонкое. Стандартный современный иврит базируется на сефардском произношении (конечное ударение), но с ашкеназскими упрощениями (потеря гортанных).', '"[{\"he\": \"שַׁבָּת: ашкеназ. «шабос», сеф. «шабат», станд. «шабат»\", \"ru\": \"Суббота: различия в произношении по традициям.\", \"translit\": \"шабат / шабос\"}, {\"he\": \"בְּנֵי בְּרַק — עִיר שֶׁבָּהּ שׁוֹמְעִים הַרְבֵּה הֲבָרָה אַשְׁכְּנָזִית\", \"ru\": \"Бней-Брак — город, где часто слышна ашкеназская фонетика.\", \"translit\": \"бней-брак — ир ше-ба шомъим hарбэ hавара ашкеназит\"}, {\"he\": \"ר׳ גְּרוֹנִית לְעוּמַת ר׳ מְבוּרְכֶּכֶת — הֶבְדֵּל בֵּין עֵדוֹת\", \"ru\": \"Увулярный Р vs. раскатистый Р — различие между общинами.\", \"translit\": \"рейш гронит леумат рейш мевурхехет — hевдель бейн эдот\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (209, 84, 'Социолекты в иврите определяются возрастом, этнической принадлежностью, уровнем религиозности и социальным классом. Регистры: גָּבוֹהַּ (высокий/литературный), תִּקְנִי (стандартный), יוֹם-יוֹמִי (разговорный), סְלֶנְג (сленг). Характерные маркеры: религиозная молодёжь использует «אַחִי» (брат мой), арабо-израильский иврит сохраняет ع и ح, молодёжный сленг активно заимствует из английского.', '"[{\"he\": \"אַחִי, מָה הַמַּצָּב? — סְלֶנְג צָעִיר דָּתִי\", \"ru\": \"Братан, как дела? — сленг молодых религиозных.\", \"translit\": \"ахи, ма hа-мацав? — сленг цаир дати\"}, {\"he\": \"יָאללָה, בּוֹא נֵלֵךְ — הַשְׁפָּעָה עֲרָבִית בְּעִבְרִית יוֹם-יוֹמִית\", \"ru\": \"Ялла, пошли — влияние арабского на повседневный иврит.\", \"translit\": \"яла, бо нелех — hашпаа аравит бе-иврит йом-йомит\"}, {\"he\": \"זֶה סוֹפֵּר קוּל, אֲנִי טוֹטָלִי מְכוּרָה עַל הַסֵּפֶר הַזֶּה\", \"ru\": \"Это очень крутой писатель, я полностью подсела на эту книгу.\", \"translit\": \"зэ сопер куль, ани тотали мехура аль hа-сефер hа-зэ\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (210, 85, 'Иврит испытал мощное влияние контактных языков: из арабского — лексика (רַמְזוֹר — светофор, от رمز «символ»), синтаксис масдаров; из идиша — фразеологизмы и дискурсивные маркеры (נוּ — ну, «так что?»); из русского — слова (בַּלָּגָן — беспорядок, פְּרוֹטֶקְצְיָה — протекция). Кальки — дословные переводы — особенно продуктивны: שׁוּק הַהוֹן (рынок капитала) — калька с английского «capital market».', '"[{\"he\": \"יֵשׁ בַּלָּגָן בַּמִּשְׂרָד — מִלָּה רוּסִית שֶׁנִּכְנְסָה לָעִבְרִית\", \"ru\": \"В офисе бардак — русское слово, вошедшее в иврит.\", \"translit\": \"йеш балаган ба-мисрад — мила русит ше-нихнеса ла-иврит\"}, {\"he\": \"נוּ, אָז מָה הֶחְלַטְתָּ? — הַשְׁפָּעַת יִידִישׁ\", \"ru\": \"Ну, так что ты решил? — влияние идиша.\", \"translit\": \"ну, аз ма hехлатта? — hашпаат йидиш\"}, {\"he\": \"הָרַמְזוֹר אָדוֹם — עָצוֹר! מִלָּה עֲרָבִית בְּשִׁמּוּשׁ יוֹם-יוֹמִי\", \"ru\": \"Светофор красный — стой! Арабское слово в повседневном употреблении.\", \"translit\": \"hа-рамзор адом — ацор! мила аравит бе-шимуш йом-йоми\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (211, 85, 'Переводческие стратегии для иврита включают: доместикацию (адаптация к ивритской морфологии: computer → מַחְשֵׁב, telephone → טֵלֵפוֹן), форенизацию (прямое заимствование: סְמָארְטְפוֹן, אִינְסְטָגְרָם), калькирование (שִׂיחַת חוּלִּין от «small talk»). Израильские переводчики часто стоят перед дилеммой: использовать ивритский неологизм Академии или прижившееся заимствование. В художественном переводе особую сложность представляет передача каламбуров и культурных реалий.', '"[{\"he\": \"\\\"הוֹזֵה בְּהָקִיץ\\\" — תַּרְגוּם הַכּוֹתֶרֶת \\\"Daydreamer\\\" לְעִבְרִית\", \"ru\": \"«Мечтатель наяву» — перевод заголовка «Daydreamer» на иврит.\", \"translit\": \"\\\"хозэ бе-hакиц\\\" — таргум hа-котерет \\\"Daydreamer\\\" ле-иврит\"}, {\"he\": \"לֹא כָּל בִּיטּוּי נִתָּן לְתַרְגֵּם מִלּוּלִית: \\\"It''s raining cats and dogs\\\"\", \"ru\": \"Не каждое выражение можно перевести дословно: «It''s raining cats and dogs».\", \"translit\": \"ло коль битуй нитан летаргем милулит\"}, {\"he\": \"\\\"שִׂיחַת חוּלִּין\\\" — קָלְקָה מֵאַנְגְּלִית שֶׁהִשְׁתַּרְשָׁה בָּעִבְרִית\", \"ru\": \"«Светская беседа» (small talk) — калька с английского, прижившаяся в иврите.\", \"translit\": \"\\\"сихат хулин\\\" — калька ме-англит ше-hиштарша ба-иврит\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (212, 86, 'Дискурс-анализ в иврите изучает, как тексты и устная речь организованы выше уровня предложения. Ключевые понятия: טוֹפִּיק (тема) и קוֹמֶנְט (рема/комментарий), סַמָּנֵי שִׁיחַ (дискурсивные маркеры: אָז, נוּ, יַאללָה, כְּאִילוּ, בְּסֵדֶר). Ивритские дискурсивные маркеры часто полисемичны: אז может означать «тогда», «так», «ну и?», «значит» в зависимости от позиции и интонации.', '"[{\"he\": \"אָז, מָה אַתָּה אוֹמֵר? — \\\"אָז\\\" כְּסַמָּן פְּתִיחָה\", \"ru\": \"Так, что ты скажешь? — «аз» как маркер начала реплики.\", \"translit\": \"аз, ма ата омер? — \\\"аз\\\" ке-саман птиха\"}, {\"he\": \"זֹאת אוֹמֶרֶת, אַתָּה לֹא מַסְכִּים? — סַמָּן הַבְהָרָה\", \"ru\": \"То есть, ты не согласен? — маркер уточнения.\", \"translit\": \"зот омерет, ата ло маским? — саман hавhара\"}, {\"he\": \"בְּקִיצוּר, הַתּוֹכְנִית לֹא עָבְדָה — סַמָּן סִיכּוּם\", \"ru\": \"Короче, план не сработал — маркер резюмирования.\", \"translit\": \"бе-кицур, hа-тохнит ло авда — саман сикум\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (213, 86, 'Риторические и аргументативные структуры в иврите: построение аргументации использует маркеры מִצַּד אֶחָד...מִצַּד שֵׁנִי (с одной стороны...с другой стороны), יֶתֵּר עַל כֵּן (более того), לְעוּמַּת זֹאת (в противовес этому), לְפִיכָךְ (следовательно). Журналистский текст строится по модели «перевёрнутой пирамиды»: кульминация в начале, детали далее. Академический дискурс использует безличные конструкции: נִרְאֶה כִּי (представляется, что), יֵשׁ לְצַיֵּין (следует отметить).', '"[{\"he\": \"יֶתֵּר עַל כֵּן, הַנְּתוּנִים מַרְאִים מַגְמָה הָפוּכָה\", \"ru\": \"Более того, данные показывают обратную тенденцию.\", \"translit\": \"йетер аль кен, hа-нтуним маръим магма hафуха\"}, {\"he\": \"נִרְאֶה כִּי הַהַשְׁעָרָה הָרִאשׁוֹנָה לֹא אוּשְּׁשָׁה\", \"ru\": \"Представляется, что первая гипотеза не подтвердилась.\", \"translit\": \"ниръэ ки hа-hашъара hа-ришона ло ушша\"}, {\"he\": \"לְפִיכָךְ, אָנוּ מְצִיעִים מוֹדֶל חָלוּפִי\", \"ru\": \"Следовательно, мы предлагаем альтернативную модель.\", \"translit\": \"лефихах, ану мециим модель халуфи\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (214, 87, 'Интернет-иврит выработал собственные конвенции: аббревиатуры и акронимы (בע"ה — בעזרת השם «с Божьей помощью», לא"ח — לא אחר כך «нет потом»), усечения (תודה → תנקס / 10x, בסדר → בס"ד), числовые замены (מ8ית → ма-шмонит → «смешно»). SMS и мессенджеры используют транслитерацию и сокращения: ביי (bye), סבבה → סבב, אחלה → אחלס.', '"[{\"he\": \"שלח לי בוואטסאפ, אני אבדוק ואחזור אליך אס\\\"ק\", \"ru\": \"Отправь мне в WhatsApp, я проверю и вернусь к тебе как можно скорее.\", \"translit\": \"шлах ли бе-ватсап, ани эвдок ве-ахзор элеха ас\\\"ак\"}, {\"he\": \"LOL זה בעברית צחוק מת, או פשוט 😂😂😂\", \"ru\": \"LOL — это по-ивритски «умираю от смеха», или просто 😂😂😂.\", \"translit\": \"LOL зэ бе-иврит цхок мет, о пашут эмоджи\"}, {\"he\": \"תגיד, למה כולם כותבים בקיצורים? — כי זה מהר יותר, אחי 🤷\", \"ru\": \"Скажи, почему все пишут сокращениями? — Потому что так быстрее, брат.\", \"translit\": \"тагид, лама кулам котвим бе-кицурим? — ки зэ маhер йотер, ахи\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (215, 87, 'Цифровая коммуникация трансформирует иврит: хештеги пишутся слитно (#אין_מצב), гендерно-инклюзивный язык использует формы с косой чертой (סטודנטים/ות) или точку (סטודנטי.ות), эмодзи заменяют интонацию и жесты. Блогеры и инфлюэнсеры создают новые речевые жанры: сторитейлинг в рилсах, тредовый формат в X (Twitter). Уникальная проблема иврита — RTL-набор (справа налево), вызывающий сложности при смешении с латиницей и цифрами.', '"[{\"he\": \"סטודנטים/ות יקרים/ות, הרישום לקורסים נפתח\", \"ru\": \"Дорогие студенты/ки, регистрация на курсы открыта (инклюзивная форма).\", \"translit\": \"студентим/-от йекарим/-от, hа-ришум ле-курсим нифтах\"}, {\"he\": \"#אין_מצב_שזה_קורה — הַהָשְׁטָג הָפַךְ לַמֵּמ\", \"ru\": \"Хештег #невозможно_что_это_происходит — стал мемом.\", \"translit\": \"хештег эйн-мацав-ше-зэ-корэ — hа-hаштаг hафах ла-мем\"}, {\"he\": \"בִּידְיוּק (BiDi) — הָאֶתְגָּר שֶׁל כְּתִיבָה דוּ-כִּוּוּנִית בָּרֶשֶׁת\", \"ru\": \"BiDi — проблема двунаправленного текста в интернете.\", \"translit\": \"биди — hа-этгар шель ктива ду-кивунит ба-решет\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (216, 88, 'Иврит принадлежит к северо-западной ветви семитской языковой семьи. Ближайшие родственники — арамейский и финикийский. С арабским (центрально-семитским) иврит разделяет трёхбуквенную корневую систему и множество когнатов: שָׁלוֹם / سَلَام (мир), סֵפֶר / سِفْر (книга), בַּיִת / بَيْت (дом). Арамейское влияние особенно сильно в талмудической лексике: כְּנֶסֶת (собрание, ← арам. כְּנִישְׁתָּא).', '"[{\"he\": \"שָׁלוֹם — סָלַאם: שֶׁתֵּי הַמִּלִּים מֵאוֹתוֹ שׁוֹרֶשׁ שמ\\\"י שׁ-ל-מ\", \"ru\": \"Шалом — Салям: оба слова от одного семитского корня Ш-Л-М.\", \"translit\": \"шалом — салам: штей hа-милим ме-ото шореш шми ш-л-м\"}, {\"he\": \"הַמִּלָּה \\\"אַבָּא\\\" קָרוֹבָה בְּכָל הַשְּׂפוֹת הַשֵּׁמִיּוֹת: אַב, أب\", \"ru\": \"Слово «отец» близко во всех семитских языках: ав, аб.\", \"translit\": \"hа-мила \\\"аба\\\" крова бе-холь hа-сфот hа-шемийот: ав, аб\"}, {\"he\": \"כנסת — מֵהָאֲרָמִית כְּנִשְׁתָּא, כְּמוֹ \\\"בֵּית כְּנֶסֶת\\\" — בֵּית תְּפִלָּה\", \"ru\": \"Кнессет — от арамейского кништа, как «синагога» — дом собрания.\", \"translit\": \"кнесет — ме-hа-арамит кништа, кмо «бейт кнесет» — бейт тфила\"}]"', '"[]"');
INSERT INTO public.grammar_rules (id, topic_id, rule_text_ru, examples_json, exceptions_json) VALUES (217, 88, 'Сравнительная семитология помогает понять закономерности ивритской морфологии и фонологии: переход ث → שׁ (арабское ثَلَاثَة — иврит שָׁלוֹשׁ «три»), соответствие ج → ג (جَمَل → גָּמָל «верблюд»), связь между эмфатическими ض-צ, ط-ט. Знание этих соответствий позволяет прогнозировать когнаты и понимать этимологию. Угаритский, аккадский и эфиопские языки дают дополнительные точки сравнения для реконструкции прасемитского.', '"[{\"he\": \"שָׁלוֹשׁ — ثَلَاثَة: ивр. שׁ = араб. ث по регулярному звуковому соответствию\", \"ru\": \"Три — саляса: ивр. Ш = араб. С по регулярному фонетическому закону.\", \"translit\": \"шалош — саляса: иврит шин = аравит та\"}, {\"he\": \"גָּמָל — جَمَل: когнаты с одинаковым значением «верблюд» в обоих языках\", \"ru\": \"Верблюд — гамаль/джамаль: когнаты с идентичным значением.\", \"translit\": \"гамаль — джамаль: когнатим им ото машмаут\"}, {\"he\": \"צַדִּיק — от корня צ-ד-ק, араб. صَدَقَ — «быть правдивым»\", \"ru\": \"Праведник — от корня Ц-Д-К, араб. садака — «быть правдивым».\", \"translit\": \"цадик — ми-шореш ц-д-к, аравит садака — «лиhйот яшар»\"}]"', '"[]"');
